import { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate, useLocation } from 'react-router-dom';
import { useAppStore } from './store/useStore';
import CustomerDashboard from './pages/CustomerDashboard';
import SellerDashboard from './pages/SellerDashboard';
import Login from './pages/Login';
import Signup from './pages/Signup';
import LandingPage from './pages/LandingPage';
import StoreSelection from './pages/StoreSelection';
import Checkout from './pages/Checkout';
import OrderConfirmation from './pages/OrderConfirmation';
import OrderTracker from './pages/OrderTracker';
import ScanHandler from './pages/ScanHandler';
import TableQRCodes from './pages/TableQRCodes';
import ReservationForm from './pages/ReservationForm';
import ReservationManager from './pages/ReservationManager';
import InventoryDashboard from './pages/InventoryDashboard';
import AdminDashboard from './pages/AdminDashboard';
import MenuBuilder from './pages/seller/MenuBuilder';
import CustomerOrders from './pages/CustomerOrders';
import DeliveryDashboard from './pages/staff/DeliveryDashboard';
import PublicDisplay from './pages/PublicDisplay';
import { Utensils, LayoutDashboard, LogOut, ShoppingBag, TerminalSquare, QrCode, Calendar, Package, Shield, Store, Menu, X, Navigation, Tv } from 'lucide-react';
import { Toaster } from 'react-hot-toast';

function ProtectedRoute({ children, role }) {
  const userRole = useAppStore(state => state.userRole);
  if (!userRole) return <div className="p-8 text-center text-slate-400">Please login to access this area.</div>;
  if (role && userRole !== role && userRole !== 'ADMIN') return <div className="p-8 text-center text-red-400">Access Denied</div>;
  return children;
}

function NavLink({ to, icon, label, bgClass, textClass, onClick }) {
  return (
    <Link onClick={onClick} to={to} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-colors ${bgClass} ${textClass}`}>
      {icon}
      <span className="font-medium">{label}</span>
    </Link>
  );
}

function TopNavigation() {
  const { token, userRole, clearAuth } = useAppStore();
  const navigate = useNavigate();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const handleLogout = () => {
    clearAuth();
    navigate('/login');
    setMobileMenuOpen(false);
  };

  const closeMenu = () => setMobileMenuOpen(false);

  return (
    <nav className="sticky top-0 z-50 glass-dark border-b border-white/5 py-4 px-4 md:px-12 flex items-center justify-between">
      <Link onClick={closeMenu} to="/" className="flex items-center gap-3 text-primary-500 hover:text-primary-400 transition-colors cursor-pointer group">
        <div className="bg-primary-500/20 p-2 rounded-xl border border-primary-500/30 overflow-hidden">
          <Utensils size={24} className="text-primary-500 relative z-10" />
        </div>
        <h1 className="text-xl font-bold tracking-wider">CHAPUU</h1>
      </Link>

      <div className="flex items-center gap-4">
        {!token ? (
          <Link to="/login" className="px-5 py-2 rounded-full bg-white/5 hover:bg-white/10 border border-white/10 text-sm font-medium transition-all">
            Login
          </Link>
        ) : (
          <>
            {/* Desktop Navigation */}
            <div className="hidden lg:flex items-center gap-4">
              <div className="flex items-center gap-2 text-sm text-slate-400 mr-2">
                <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                {userRole}
              </div>

              {userRole === 'SELLER' || userRole === 'ADMIN' ? (
                <>
                  <Link to="/seller" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-primary-600/20 text-primary-500 hover:bg-primary-600/30 transition-colors"><TerminalSquare size={16} /><span className="text-sm">POS</span></Link>
                  <Link to="/seller/reservations" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-indigo-600/20 text-indigo-400 hover:bg-indigo-600/30 transition-colors"><Calendar size={16} /><span className="text-sm">Host</span></Link>
                  <Link to="/seller/menu" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-pink-600/20 text-pink-400 hover:bg-pink-600/30 transition-colors"><Utensils size={16} /><span className="text-sm">Menu</span></Link>
                  <Link to="/seller/inventory" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-orange-600/20 text-orange-400 hover:bg-orange-600/30 transition-colors"><Package size={16} /><span className="text-sm">Stock</span></Link>
                  <Link to="/seller/qrcodes" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-white/5 hover:bg-white/10 transition-colors"><QrCode size={16} /><span className="text-sm">QRs</span></Link>
                  <Link to="/tv/1" target="_blank" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-yellow-600/20 text-yellow-500 hover:bg-yellow-600/30 transition-colors"><Tv size={16} /><span className="text-sm">TV Mode</span></Link>
                  {userRole === 'ADMIN' && (
                    <Link to="/admin" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-purple-600/20 text-purple-400 hover:bg-purple-600/30 transition-colors"><Shield size={16} /><span className="text-sm">Admin</span></Link>
                  )}
                </>
              ) : null}

              {userRole === 'CHEF' && (
                <Link to="/seller" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-primary-600/20 text-primary-500 hover:bg-primary-600/30 transition-colors"><TerminalSquare size={16} /><span className="text-sm">KDS System</span></Link>
              )}

              {userRole === 'CUSTOMER' ? (
                <>
                  <Link to="/stores" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-white/5 hover:bg-white/10 transition-colors"><Store size={16} /><span className="text-sm">Restaurants</span></Link>
                  <Link to="/orders" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-white/5 hover:bg-white/10 transition-colors"><ShoppingBag size={16} /><span className="text-sm">My Orders</span></Link>
                  <Link to="/reserve" className="flex items-center gap-2 px-3 py-2 rounded-lg bg-white/5 hover:bg-white/10 transition-colors"><Calendar size={16} /><span className="text-sm">Reserve</span></Link>
                </>
              ) : null}

              <button onClick={handleLogout} className="p-2 rounded-lg text-slate-400 hover:text-red-400 hover:bg-red-400/10 transition-colors ml-2" title="Logout">
                <LogOut size={20} />
              </button>
            </div>

            {/* Mobile Hamburger Button */}
            <div className="lg:hidden flex items-center gap-3">
              <div className="flex items-center gap-2 text-xs text-slate-400">
                <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                {userRole}
              </div>
              <button
                onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
                className="p-2 bg-white/5 rounded-xl text-slate-300 hover:text-white transition-colors"
              >
                {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </>
        )}
      </div>

      {/* Mobile Menu Dropdown */}
      {mobileMenuOpen && token && (
        <div className="absolute top-[100%] left-0 w-full bg-dark-950 border-b border-white/5 shadow-2xl p-4 flex flex-col gap-2 lg:hidden animate-in slide-in-from-top-4 duration-200">

          {userRole === 'SELLER' || userRole === 'ADMIN' ? (
            <div className="grid grid-cols-2 gap-2 mb-2">
              <NavLink to="/seller" icon={<TerminalSquare size={18} />} label="POS System" bgClass="bg-primary-600/10 hover:bg-primary-600/20" textClass="text-primary-400" onClick={closeMenu} />
              <NavLink to="/seller/reservations" icon={<Calendar size={18} />} label="Host Stand" bgClass="bg-indigo-600/10 hover:bg-indigo-600/20" textClass="text-indigo-400" onClick={closeMenu} />
              <NavLink to="/seller/menu" icon={<Utensils size={18} />} label="Menu Builder" bgClass="bg-pink-600/10 hover:bg-pink-600/20" textClass="text-pink-400" onClick={closeMenu} />
              <NavLink to="/seller/inventory" icon={<Package size={18} />} label="Stock Manage" bgClass="bg-orange-600/10 hover:bg-orange-600/20" textClass="text-orange-400" onClick={closeMenu} />
              <NavLink to="/seller/qrcodes" icon={<QrCode size={18} />} label="Table QRs" bgClass="bg-white/5 hover:bg-white/10" textClass="text-slate-200" onClick={closeMenu} />
              <NavLink to="/tv/1" icon={<Tv size={18} />} label="Launch TV Dashboard" bgClass="bg-yellow-600/10 hover:bg-yellow-600/20" textClass="text-yellow-500" onClick={closeMenu} />
              {userRole === 'ADMIN' && (
                <NavLink to="/admin" icon={<Shield size={18} />} label="Platform Admin" bgClass="bg-purple-600/10 hover:bg-purple-600/20" textClass="text-purple-400 col-span-2 justify-center" onClick={closeMenu} />
              )}
            </div>
          ) : null}

          {userRole === 'CHEF' && (
            <div className="flex flex-col gap-2 mb-2">
              <NavLink to="/seller" icon={<TerminalSquare size={18} />} label="KDS System" bgClass="bg-primary-600/10 hover:bg-primary-600/20" textClass="text-primary-400" onClick={closeMenu} />
            </div>
          )}

          {userRole === 'CUSTOMER' ? (
            <div className="flex flex-col gap-2 mb-2">
              <NavLink to="/stores" icon={<Store size={18} />} label="Restaurants" bgClass="bg-white/5 hover:bg-white/10" textClass="text-slate-200" onClick={closeMenu} />
              <NavLink to="/orders" icon={<ShoppingBag size={18} />} label="My Orders" bgClass="bg-white/5 hover:bg-white/10" textClass="text-slate-200" onClick={closeMenu} />
              <NavLink to="/reserve" icon={<Calendar size={18} />} label="Reserve Table" bgClass="bg-white/5 hover:bg-white/10" textClass="text-slate-200" onClick={closeMenu} />
            </div>
          ) : null}

          {userRole === 'DELIVERY' ? (
            <div className="flex flex-col gap-2 mb-2">
              <NavLink to="/delivery" icon={<Navigation size={18} />} label="Deliveries" bgClass="bg-green-600/10 hover:bg-green-600/20" textClass="text-green-400" onClick={closeMenu} />
            </div>
          ) : null}

          <button onClick={handleLogout} className="flex items-center justify-center gap-2 p-3 mt-2 rounded-xl text-red-400 bg-red-400/10 hover:bg-red-400/20 transition-colors font-medium">
            <LogOut size={18} /> Sign Out
          </button>
        </div>
      )}
    </nav>
  );
}

function App() {
  return (
    <Router>
      <div className="flex flex-col min-h-screen">
        <TopNavigation />
        <Toaster position="bottom-right" toastOptions={{
          style: { background: '#1e293b', color: '#fff', border: '1px solid rgba(255,255,255,0.1)' },
          success: { iconTheme: { primary: '#22c55e', secondary: '#fff' } }
        }} />

        <main className="flex-1 w-full max-w-[1600px] mx-auto p-4 sm:p-6 lg:p-8">
          <Routes>
            {/* Public App Routes */}
            <Route path="/" element={<LandingPage />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Signup />} />
            <Route path="/tv/:storeId?" element={<PublicDisplay />} />

            {/* Protected Role-Based Routes */}
            <Route path="/stores" element={<ProtectedRoute role="CUSTOMER"><StoreSelection /></ProtectedRoute>} />
            <Route path="/menu" element={<ProtectedRoute role="CUSTOMER"><CustomerDashboard /></ProtectedRoute>} />
            <Route path="/checkout" element={<ProtectedRoute role="CUSTOMER"><Checkout /></ProtectedRoute>} />
            <Route path="/orders" element={<ProtectedRoute role="CUSTOMER"><CustomerOrders /></ProtectedRoute>} />
            <Route path="/order/confirmation/:id" element={<ProtectedRoute role="CUSTOMER"><OrderConfirmation /></ProtectedRoute>} />
            <Route path="/order/track/:id" element={<ProtectedRoute role="CUSTOMER"><OrderTracker /></ProtectedRoute>} />
            <Route path="/scan" element={<ProtectedRoute role="CUSTOMER"><ScanHandler /></ProtectedRoute>} />
            <Route path="/reserve" element={<ProtectedRoute role="CUSTOMER"><ReservationForm /></ProtectedRoute>} />
            <Route path="/seller" element={<ProtectedRoute><SellerDashboard /></ProtectedRoute>} />
            <Route path="/seller/menu" element={<ProtectedRoute role="SELLER"><MenuBuilder /></ProtectedRoute>} />
            <Route path="/seller/reservations" element={<ProtectedRoute role="SELLER"><ReservationManager /></ProtectedRoute>} />
            <Route path="/seller/inventory" element={<ProtectedRoute role="SELLER"><InventoryDashboard /></ProtectedRoute>} />
            <Route path="/seller/qrcodes" element={<ProtectedRoute role="SELLER"><TableQRCodes /></ProtectedRoute>} />
            <Route path="/admin" element={<ProtectedRoute role="ADMIN"><AdminDashboard /></ProtectedRoute>} />

            {/* Delivery Routes */}
            <Route path="/delivery" element={<ProtectedRoute role="DELIVERY"><DeliveryDashboard /></ProtectedRoute>} />
          </Routes>
        </main>
      </div>
    </Router>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Shield, Store, Users, UserPlus, Home, Save, BarChart3, TrendingUp, DollarSign } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Legend, PieChart, Pie, Cell } from 'recharts';
import toast from 'react-hot-toast';
import apiClient from '../api/client';

export default function AdminDashboard() {
    const [stores, setStores] = useState([]);
    const [users, setUsers] = useState([]);
    const [orders, setOrders] = useState([]);
    const [selectedOwner, setSelectedOwner] = useState('');

    // Dashboard View State
    const [activeTab, setActiveTab] = useState('MANAGEMENT'); // 'MANAGEMENT' or 'ANALYTICS'

    // New Seller Form State
    const [newUsername, setNewUsername] = useState('');
    const [newPassword, setNewPassword] = useState('');

    // New Store Form State
    const [newStoreName, setNewStoreName] = useState('');
    const [newStoreAddress, setNewStoreAddress] = useState('');
    const [newContactPhone, setNewContactPhone] = useState('');
    const [newContactEmail, setNewContactEmail] = useState('');
    const [newStoreImage, setNewStoreImage] = useState(null);

    // Edit Store State
    const [editingStore, setEditingStore] = useState(null);
    const [editStoreData, setEditStoreData] = useState({ name: '', location: '', contact_phone: '', contact_email: '' });
    const [editStoreImage, setEditStoreImage] = useState(null);

    const fetchData = () => {
        apiClient.get('/stores/')
            .then(res => setStores(res.data))
            .catch(err => console.error("Failed to load stores", err));

        apiClient.get('/users/')
            .then(res => setUsers(res.data))
            .catch(err => console.error("Failed to load users", err));

        apiClient.get('/orders/')
            .then(res => setOrders(res.data))
            .catch(err => console.error("Failed to load orders", err));
    };

    useEffect(() => {
        fetchData();
        const interval = setInterval(fetchData, 10000);
        return () => clearInterval(interval);
    }, []);

    const handleCreateSeller = (e) => {
        e.preventDefault();
        apiClient.post('/users/', {
            username: newUsername,
            password: newPassword,
            role: 'SELLER'
        })
            .then(res => {
                toast.success(`Seller ${newUsername} created successfully!`);
                setNewUsername('');
                setNewPassword('');
                fetchData();
            })
            .catch(err => toast.error("Failed to create seller user."));
    };

    const handleCreateStore = (e) => {
        e.preventDefault();

        const formData = new FormData();
        formData.append('name', newStoreName);
        formData.append('location', newStoreAddress);
        formData.append('owner', selectedOwner);
        formData.append('is_active', true);
        if (newContactPhone) formData.append('contact_phone', newContactPhone);
        if (newContactEmail) formData.append('contact_email', newContactEmail);
        if (newStoreImage) formData.append('image', newStoreImage);

        apiClient.post('/stores/', formData, {
            headers: { 'Content-Type': 'multipart/form-data' }
        })
            .then(res => {
                toast.success(`Store ${newStoreName} created!`);
                setNewStoreName('');
                setNewStoreAddress('');
                setNewContactPhone('');
                setNewContactEmail('');
                setNewStoreImage(null);
                setSelectedOwner('');
                fetchData();
            })
            .catch(err => toast.error("Failed to create store."));
    };

    const handleUpdateStore = (e) => {
        e.preventDefault();
        const formData = new FormData();
        formData.append('name', editStoreData.name);
        formData.append('location', editStoreData.location);
        formData.append('contact_phone', editStoreData.contact_phone);
        formData.append('contact_email', editStoreData.contact_email);
        if (editStoreImage) {
            formData.append('image', editStoreImage);
        }

        apiClient.patch(`/stores/${editingStore.id}/`, formData, {
            headers: { 'Content-Type': 'multipart/form-data' }
        })
            .then(res => {
                toast.success(`Store updated!`);
                setEditingStore(null);
                setEditStoreImage(null);
                fetchData();
            })
            .catch(err => toast.error("Failed to update store."));
    };

    const sellers = users.filter(u => u.role === 'SELLER' || u.role === 'ADMIN');

    return (
        <div className="w-full min-h-screen py-6 px-4">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
                <h1 className="text-3xl font-bold flex items-center gap-3 text-white">
                    <Shield className="text-purple-500" /> Platform Admin Center
                </h1>

                <div className="flex bg-dark-900 border border-white/10 rounded-xl p-1">
                    <button
                        onClick={() => setActiveTab('MANAGEMENT')}
                        className={`px-6 py-2 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 ${activeTab === 'MANAGEMENT' ? 'bg-purple-600 text-white' : 'text-slate-400 hover:text-white'}`}
                    >
                        <Store size={16} /> Management
                    </button>
                    <button
                        onClick={() => setActiveTab('ANALYTICS')}
                        className={`px-6 py-2 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 ${activeTab === 'ANALYTICS' ? 'bg-purple-600 text-white' : 'text-slate-400 hover:text-white'}`}
                    >
                        <BarChart3 size={16} /> Advanced Analytics
                    </button>
                </div>
            </div>

            {activeTab === 'MANAGEMENT' ? (
                <>
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
                        {/* Onboard User Board */}
                        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="glass-dark border border-white/5 rounded-3xl p-6">
                            <h2 className="text-xl font-bold mb-6 text-white flex items-center gap-2"><UserPlus className="text-blue-400" /> Mint Vendor Account</h2>

                            <form onSubmit={handleCreateSeller} className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-400 mb-1">Temporary Username</label>
                                    <input
                                        type="text"
                                        required
                                        value={newUsername}
                                        onChange={e => setNewUsername(e.target.value)}
                                        className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-blue-500"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-400 mb-1">Temporary Password</label>
                                    <input
                                        type="password"
                                        required
                                        value={newPassword}
                                        onChange={e => setNewPassword(e.target.value)}
                                        className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-blue-500"
                                    />
                                </div>
                                <button type="submit" className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-medium transition-colors">
                                    Provision Seller Account
                                </button>
                            </form>
                        </motion.div>

                        {/* Create Store Board */}
                        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }} className="glass-dark border border-white/5 rounded-3xl p-6">
                            <h2 className="text-xl font-bold mb-6 text-white flex items-center gap-2"><Store className="text-green-400" /> Register New Store</h2>

                            <form onSubmit={handleCreateStore} className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-400 mb-1">Store Name</label>
                                    <input
                                        type="text"
                                        required
                                        value={newStoreName}
                                        onChange={e => setNewStoreName(e.target.value)}
                                        className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-green-500"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-400 mb-1">Address / Location</label>
                                    <input
                                        type="text"
                                        required
                                        value={newStoreAddress}
                                        onChange={e => setNewStoreAddress(e.target.value)}
                                        className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-green-500"
                                    />
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-400 mb-1">Contact Phone</label>
                                        <input
                                            type="tel"
                                            value={newContactPhone}
                                            onChange={e => setNewContactPhone(e.target.value)}
                                            className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-green-500"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-400 mb-1">Contact Email</label>
                                        <input
                                            type="email"
                                            value={newContactEmail}
                                            onChange={e => setNewContactEmail(e.target.value)}
                                            className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-green-500"
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-400 mb-1">Store Profile Image</label>
                                    <input
                                        type="file"
                                        accept="image/*"
                                        onChange={e => setNewStoreImage(e.target.files[0])}
                                        className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-green-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-green-500/10 file:text-green-500 hover:file:bg-green-500/20"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-400 mb-1">Assign to Vendor</label>
                                    <select
                                        required
                                        value={selectedOwner}
                                        onChange={e => setSelectedOwner(e.target.value)}
                                        className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-green-500"
                                    >
                                        <option value="" disabled>Select User</option>
                                        {sellers.map(s => (
                                            <option key={s.id} value={s.id}>{s.username} (ID: {s.id})</option>
                                        ))}
                                    </select>
                                </div>
                                <button type="submit" className="w-full py-3 bg-green-600 hover:bg-green-700 text-white rounded-xl font-medium transition-colors">
                                    Launch Store Instances
                                </button>
                            </form>
                        </motion.div>
                    </div>

                    <div className="glass-dark border border-white/5 rounded-3xl p-6">
                        <h2 className="text-xl font-bold mb-6 text-white flex items-center gap-2"><Home className="text-purple-400" /> Active Platform Tenants</h2>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {stores.map(s => (
                                <div key={s.id} className="p-4 bg-white/5 rounded-2xl border border-white/10 hover:border-purple-500/50 transition-colors flex flex-col">
                                    {s.image && (
                                        <img src={s.image} alt={s.name} className="w-full h-32 object-cover rounded-xl mb-3 border border-white/5" />
                                    )}
                                    <h3 className="font-bold text-lg mb-1">{s.name}</h3>
                                    <p className="text-sm text-slate-400 mb-1">{s.address}</p>
                                    <p className="text-xs text-slate-500 mb-3">{s.contact_phone} | {s.contact_email}</p>
                                    <div className="flex justify-between items-center text-xs mt-auto pt-2 border-t border-white/5">
                                        <span className="px-2 py-1 bg-green-500/20 text-green-400 rounded-md">Live Platform Node</span>
                                        <div className="flex items-center gap-2">
                                            <span className="text-slate-500">Owner ID: {s.owner}</span>
                                            <button
                                                onClick={() => {
                                                    setEditingStore(s);
                                                    setEditStoreData({ name: s.name, location: s.location, contact_phone: s.contact_phone || '', contact_email: s.contact_email || '' });
                                                }}
                                                className="px-2 py-1 bg-blue-500/20 text-blue-400 rounded-md hover:bg-blue-500/30 transition-colors"
                                            >
                                                Edit
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="glass-dark border border-white/5 rounded-3xl p-6 mt-8">
                        <h2 className="text-xl font-bold mb-6 text-white flex items-center gap-2">Global Live Orders</h2>
                        <div className="overflow-x-auto">
                            <table className="w-full text-left text-sm text-slate-300">
                                <thead className="bg-white/5 text-slate-400">
                                    <tr>
                                        <th className="p-4 rounded-tl-xl font-medium">Order ID</th>
                                        <th className="p-4 font-medium">Store</th>
                                        <th className="p-4 font-medium">Total Amount</th>
                                        <th className="p-4 font-medium">Status</th>
                                        <th className="p-4 rounded-tr-xl font-medium">Time</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {orders.slice(0, 15).map(o => (
                                        <tr key={o.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                                            <td className="p-4 font-mono text-primary-400">#{o.id.toString().padStart(4, '0')}</td>
                                            <td className="p-4">{stores.find(s => s.id === o.store)?.name || o.store}</td>
                                            <td className="p-4">${o.total_amount}</td>
                                            <td className="p-4">
                                                <span className={`px-2 py-1 bg-white/10 rounded-lg text-xs font-semibold
                                            ${o.state === 'CANCELLED' ? 'text-red-400' : ''}
                                            ${o.state === 'COMPLETED' ? 'text-green-400' : ''}
                                            ${o.state === 'AWAITING_PAYMENT' ? 'text-orange-400' : ''}
                                            ${o.state === 'PREPARING' || o.state === 'QUEUED' ? 'text-indigo-400' : ''}
                                            ${o.state === 'READY' ? 'text-teal-400' : ''}
                                        `}>
                                                    {o.state.replace('_', ' ')}
                                                </span>
                                            </td>
                                            <td className="p-4 text-slate-500">{new Date(o.created_at).toLocaleTimeString()}</td>
                                        </tr>
                                    ))}
                                    {orders.length === 0 && (
                                        <tr>
                                            <td colSpan="5" className="p-8 text-center text-slate-500">No recent platform orders found.</td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </>
            ) : (
                <div className="flex flex-col gap-6">
                    {/* Key Metrics Row */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="glass-dark border border-white/5 rounded-3xl p-6 relative overflow-hidden">
                            <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/10 rounded-full blur-2xl -mr-10 -mt-10"></div>
                            <div className="flex justify-between items-start relative z-10">
                                <div>
                                    <p className="text-slate-400 text-sm font-medium mb-1">Total Platform Volume</p>
                                    <h3 className="text-4xl font-bold text-white mb-2">
                                        ${orders.filter(o => o.state === 'COMPLETED').reduce((sum, o) => sum + parseFloat(o.total_amount), 0).toFixed(2)}
                                    </h3>
                                    <div className="flex items-center gap-1 text-xs text-green-400 font-medium">
                                        <TrendingUp size={14} /> +All Time
                                    </div>
                                </div>
                                <div className="p-3 bg-purple-500/20 text-purple-400 rounded-xl">
                                    <DollarSign size={24} />
                                </div>
                            </div>
                        </div>

                        <div className="glass-dark border border-white/5 rounded-3xl p-6 relative overflow-hidden">
                            <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 rounded-full blur-2xl -mr-10 -mt-10"></div>
                            <div className="flex justify-between items-start relative z-10">
                                <div>
                                    <p className="text-slate-400 text-sm font-medium mb-1">Total Orders</p>
                                    <h3 className="text-4xl font-bold text-white mb-2">
                                        {orders.length}
                                    </h3>
                                    <div className="flex items-center gap-1 text-xs text-blue-400 font-medium tracking-wide border border-blue-500/30 bg-blue-500/10 px-2 py-0.5 rounded-md">
                                        Lifetime Orders
                                    </div>
                                </div>
                                <div className="p-3 bg-blue-500/20 text-blue-400 rounded-xl">
                                    <ListOrdered size={24} />
                                </div>
                            </div>
                        </div>

                        <div className="glass-dark border border-white/5 rounded-3xl p-6 relative overflow-hidden">
                            <div className="absolute top-0 right-0 w-32 h-32 bg-orange-500/10 rounded-full blur-2xl -mr-10 -mt-10"></div>
                            <div className="flex justify-between items-start relative z-10">
                                <div>
                                    <p className="text-slate-400 text-sm font-medium mb-1">Active Tenants</p>
                                    <h3 className="text-4xl font-bold text-white mb-2">
                                        {stores.filter(s => s.is_active).length}
                                    </h3>
                                    <div className="flex items-center gap-1 text-xs text-orange-400 font-medium tracking-wide">
                                        Operating Across Platform
                                    </div>
                                </div>
                                <div className="p-3 bg-orange-500/20 text-orange-400 rounded-xl">
                                    <Home size={24} />
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Charts Row */}
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="glass-dark border border-white/5 rounded-3xl p-6 h-[400px]">
                            <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2"><TrendingUp size={18} className="text-purple-400" /> Revenue vs Order Volume (Last 10 Orders)</h3>
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={orders.slice(0, 10).reverse().map(o => ({
                                    name: `#${o.id}`,
                                    revenue: parseFloat(o.total_amount),
                                    items: o.items?.length || 1
                                }))}>
                                    <defs>
                                        <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#a855f7" stopOpacity={0.3} />
                                            <stop offset="95%" stopColor="#a855f7" stopOpacity={0} />
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#ffffff10" vertical={false} />
                                    <XAxis dataKey="name" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                                    <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(value) => `$${value}`} />
                                    <Tooltip
                                        contentStyle={{ backgroundColor: '#0f172a', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '12px' }}
                                        itemStyle={{ color: '#e2e8f0' }}
                                    />
                                    <Area type="monotone" dataKey="revenue" stroke="#a855f7" strokeWidth={3} fillOpacity={1} fill="url(#colorRevenue)" />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>

                        <div className="glass-dark border border-white/5 rounded-3xl p-6 h-[400px]">
                            <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2"><Store size={18} className="text-blue-400" /> Gross Merchandise Value (GMV) by Store</h3>
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={stores.map(s => {
                                    const storeOrders = orders.filter(o => o.store === s.id && o.state === 'COMPLETED');
                                    const revenue = storeOrders.reduce((sum, o) => sum + parseFloat(o.total_amount), 0);
                                    return { name: s.name, GMV: revenue };
                                }).filter(d => d.GMV > 0)}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#ffffff10" vertical={false} />
                                    <XAxis dataKey="name" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                                    <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(value) => `$${value}`} />
                                    <Tooltip
                                        cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                                        contentStyle={{ backgroundColor: '#0f172a', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '12px' }}
                                    />
                                    <Bar dataKey="GMV" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </div>
            )}

            {/* Edit Store Modal */}
            {editingStore && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-dark-950/80 backdrop-blur-sm">
                    <motion.div initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} className="bg-dark-900 border border-white/10 rounded-3xl p-8 max-w-lg w-full shadow-2xl relative">
                        <h2 className="text-2xl font-bold text-white mb-6">Edit Tenant: {editingStore.name}</h2>
                        <form onSubmit={handleUpdateStore} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-400 mb-1">Store Name</label>
                                <input type="text" value={editStoreData.name} onChange={e => setEditStoreData({ ...editStoreData, name: e.target.value })} className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-blue-500" />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-400 mb-1">Location</label>
                                <input type="text" value={editStoreData.location} onChange={e => setEditStoreData({ ...editStoreData, location: e.target.value })} className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-blue-500" />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-400 mb-1">Contact Phone</label>
                                    <input type="text" value={editStoreData.contact_phone} onChange={e => setEditStoreData({ ...editStoreData, contact_phone: e.target.value })} className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-blue-500" />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-400 mb-1">Contact Email</label>
                                    <input type="email" value={editStoreData.contact_email} onChange={e => setEditStoreData({ ...editStoreData, contact_email: e.target.value })} className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-blue-500" />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-400 mb-1">Update Premium Underlay Image</label>
                                <input type="file" accept="image/*" onChange={e => setEditStoreImage(e.target.files[0])} className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:bg-blue-500/10 file:text-blue-500 text-sm" />
                            </div>

                            <div className="flex gap-4 pt-4 mt-6 border-t border-white/5">
                                <button type="button" onClick={() => { setEditingStore(null); setEditStoreImage(null); }} className="flex-1 py-3 text-slate-400 hover:text-white transition-colors font-medium">Cancel</button>
                                <button type="submit" className="flex-1 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-medium shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2"><Save size={18} /> Update Tenant</button>
                            </div>
                        </form>
                    </motion.div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Package, Plus, Minus, Power, AlertTriangle, Search } from 'lucide-react';
import toast from 'react-hot-toast';
import apiClient from '../api/client';

export default function InventoryDashboard() {
    const [inventory, setInventory] = useState([]);
    const [products, setProducts] = useState([]);
    const [ingredients, setIngredients] = useState([]);
    const [recipes, setRecipes] = useState([]);
    const [activeTab, setActiveTab] = useState('stock'); // 'stock' or 'recipes'
    const [search, setSearch] = useState('');
    const [storeId, setStoreId] = useState(null);

    const [newIngredient, setNewIngredient] = useState({ name: '', unit_of_measure: '', image: null });
    const [newRecipe, setNewRecipe] = useState({ product: '', ingredient: '', quantity_required: '' });

    const fetchData = () => {
        apiClient.get('/stores/')
            .then(res => {
                if (res.data.length > 0) setStoreId(res.data[0].id);
            });

        apiClient.get('/inventory/')
            .then(res => setInventory(res.data))
            .catch(err => console.error("Failed to load inventory:", err));

        apiClient.get('/products/')
            .then(res => setProducts(res.data))
            .catch(err => console.error("Failed to load products:", err));

        apiClient.get('/ingredients/')
            .then(res => setIngredients(res.data))
            .catch(err => console.error("Failed to load ingredients:", err));

        apiClient.get('/recipes/')
            .then(res => setRecipes(res.data))
            .catch(err => console.error("Failed to load recipes:", err));
    };

    useEffect(() => {
        fetchData();
        const interval = setInterval(fetchData, 10000);
        return () => clearInterval(interval);
    }, []);

    const handleAdjustStock = (stockId, adjustment) => {
        apiClient.post(`/inventory/${stockId}/adjust/`, { adjustment })
            .then(res => {
                toast.success(`Stock adjusted by ${adjustment > 0 ? '+' : ''}${adjustment}`);
                fetchData();
            })
            .catch(err => toast.error(err.response?.data?.error || "Failed to adjust stock"));
    };

    const handleToggleProduct = (productId) => {
        apiClient.post(`/products/${productId}/toggle_status/`)
            .then(res => {
                toast.success(res.data.is_active ? "Product is now Active" : "Product marked Out-of-Stock");
                fetchData();
            })
            .catch(err => toast.error("Failed to toggle product status"));
    };

    const handleCreateIngredient = (e) => {
        e.preventDefault();
        if (!storeId) {
            toast.error("No store active for this user.");
            return;
        }

        const formData = new FormData();
        formData.append('name', newIngredient.name);
        formData.append('unit_of_measure', newIngredient.unit_of_measure);
        formData.append('store', storeId);
        if (newIngredient.image) {
            formData.append('image', newIngredient.image);
        }

        apiClient.post('/ingredients/', formData, {
            headers: { 'Content-Type': 'multipart/form-data' }
        })
            .then(res => {
                toast.success('Ingredient created!');
                setNewIngredient({ name: '', unit_of_measure: '', image: null });
                fetchData();
            })
            .catch(err => toast.error('Failed to create ingredient'));
    };

    const handleCreateRecipe = (e) => {
        e.preventDefault();
        apiClient.post('/recipes/', newRecipe)
            .then(res => {
                toast.success('Recipe linked!');
                setNewRecipe({ product: '', ingredient: '', quantity_required: '' });
                fetchData();
            })
            .catch(err => toast.error('Failed to link recipe'));
    };

    const handleDeleteRecipe = (id) => {
        apiClient.delete(`/recipes/${id}/`)
            .then(() => {
                toast.success('Recipe unlinked');
                fetchData();
            })
            .catch(err => toast.error('Failed to unlink recipe'));
    };

    const filteredProducts = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
    const filteredInventory = inventory.filter(i =>
        (i.product_name && i.product_name.toLowerCase().includes(search.toLowerCase())) ||
        (i.ingredient_name && i.ingredient_name.toLowerCase().includes(search.toLowerCase()))
    );
    const filteredIngredients = ingredients.filter(ing => ing.name.toLowerCase().includes(search.toLowerCase()));
    const filteredRecipesProducts = products.filter(p =>
        recipes.some(r => r.product === p.id) &&
        (p.name.toLowerCase().includes(search.toLowerCase()) || recipes.some(r => r.product === p.id && r.ingredient_name && r.ingredient_name.toLowerCase().includes(search.toLowerCase())))
    );

    return (
        <div className="w-full min-h-screen py-6 px-4">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
                <h1 className="text-3xl font-bold flex items-center gap-3"><Package className="text-orange-500" /> Stock Management</h1>

                <div className="relative w-full md:w-64">
                    <Search className="absolute left-3 top-3 text-slate-400" size={18} />
                    <input
                        type="text"
                        placeholder="Search items..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="w-full bg-black/20 border border-white/10 rounded-xl pl-10 pr-4 py-2 text-white focus:outline-none focus:border-orange-500"
                    />
                </div>
            </div>

            <div className="flex gap-4 mb-6 border-b border-white/10 pb-4 overflow-x-auto">
                <button
                    onClick={() => setActiveTab('stock')}
                    className={`px-6 py-2 rounded-xl font-medium transition-colors whitespace-nowrap ${activeTab === 'stock' ? 'bg-orange-500 text-white shadow-lg shadow-orange-500/20' : 'bg-white/5 text-slate-400 hover:text-white hover:bg-white/10'}`}
                >
                    Stock & Availability
                </button>
                <button
                    onClick={() => setActiveTab('recipes')}
                    className={`px-6 py-2 rounded-xl font-medium transition-colors whitespace-nowrap ${activeTab === 'recipes' ? 'bg-orange-500 text-white shadow-lg shadow-orange-500/20' : 'bg-white/5 text-slate-400 hover:text-white hover:bg-white/10'}`}
                >
                    Ingredients & Recipes
                </button>
            </div>

            {activeTab === 'stock' ? (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

                    {/* Product Availability Toggle */}
                    <div className="glass-dark border border-white/5 rounded-3xl p-6">
                        <h2 className="text-xl font-bold mb-4 text-white flex justify-between items-center">
                            Menu Availability
                            <span className="text-sm font-normal text-slate-400">Toggle Out-of-Stock</span>
                        </h2>

                        <div className="space-y-3 max-h-[600px] overflow-y-auto custom-scrollbar pr-2">
                            {filteredProducts.map(p => (
                                <motion.div layout key={p.id} className={`flex items-center justify-between p-4 rounded-xl border transition-colors ${p.is_active ? 'bg-white/5 border-white/10' : 'bg-red-500/10 border-red-500/30'}`}>
                                    <div>
                                        <h3 className={`font-semibold ${!p.is_active && 'text-red-400 line-through'}`}>{p.name}</h3>
                                        <p className="text-sm text-slate-400">${p.price}</p>
                                    </div>

                                    <button
                                        onClick={() => handleToggleProduct(p.id)}
                                        className={`p-3 rounded-xl flex items-center gap-2 transition-all ${p.is_active ? 'bg-green-500/20 text-green-400 hover:bg-green-500/30' : 'bg-red-500/30 text-red-400 hover:bg-red-500/40'}`}
                                    >
                                        <Power size={18} />
                                        {p.is_active ? 'Active' : 'Disabled'}
                                    </button>
                                </motion.div>
                            ))}
                        </div>
                    </div>

                    {/* Raw Inventory Counts */}
                    <div className="glass-dark border border-white/5 rounded-3xl p-6">
                        <h2 className="text-xl font-bold mb-4 text-white flex justify-between items-center">
                            Physical Stock Counts
                            <span className="text-sm font-normal text-slate-400">Restock / Waste</span>
                        </h2>

                        <div className="space-y-3 max-h-[600px] overflow-y-auto custom-scrollbar pr-2">
                            {filteredInventory.map(inv => {
                                const isLow = inv.quantity <= inv.low_stock_threshold;
                                return (
                                    <motion.div layout key={inv.id} className={`flex flex-col sm:flex-row sm:items-center justify-between p-4 rounded-xl border ${isLow ? 'bg-orange-500/10 border-orange-500/30' : 'bg-white/5 border-white/10'}`}>
                                        <div className="mb-3 sm:mb-0">
                                            <h3 className="font-semibold">{inv.product_name || inv.ingredient_name}</h3>
                                            <p className="text-sm text-slate-400">Tracking: {inv.product ? 'End Product' : 'Raw Ingredient'}</p>
                                        </div>

                                        <div className="flex items-center gap-4">
                                            <div className="flex flex-col items-end mr-2">
                                                <span className={`text-xl font-bold ${isLow ? 'text-orange-400' : 'text-primary-400'}`}>{parseFloat(inv.quantity).toFixed(0)}</span>
                                                {isLow && <span className="text-xs text-orange-400 flex items-center gap-1"><AlertTriangle size={12} /> Low Stock!</span>}
                                            </div>

                                            <div className="flex items-center bg-black/40 rounded-lg overflow-hidden border border-white/10">
                                                <button onClick={() => handleAdjustStock(inv.id, -1)} className="p-2 hover:bg-white/10 text-red-400 transition-colors"><Minus size={16} /></button>
                                                <button onClick={() => handleAdjustStock(inv.id, -10)} className="px-2 py-2 hover:bg-white/10 text-red-400 text-xs font-bold border-x border-white/5 transition-colors">-10</button>
                                                <button onClick={() => handleAdjustStock(inv.id, 10)} className="px-2 py-2 hover:bg-white/10 text-green-400 text-xs font-bold border-r border-white/5 transition-colors">+10</button>
                                                <button onClick={() => handleAdjustStock(inv.id, 1)} className="p-2 hover:bg-white/10 text-green-400 transition-colors"><Plus size={16} /></button>
                                            </div>
                                        </div>
                                    </motion.div>
                                );
                            })}
                            {filteredInventory.length === 0 && (
                                <div className="text-center py-10 text-slate-500">No inventory tracked items found.</div>
                            )}
                        </div>
                    </div>

                </div>
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    {/* Ingredients Column */}
                    <div className="flex flex-col gap-6">
                        <div className="glass-dark border border-white/5 rounded-3xl p-6">
                            <h2 className="text-xl font-bold mb-4 text-white">Create Ingredient</h2>
                            <form onSubmit={handleCreateIngredient} className="flex flex-col gap-4">
                                <div className="flex flex-col sm:flex-row gap-4">
                                    <input
                                        type="text"
                                        placeholder="Name (e.g. Flour)"
                                        required
                                        value={newIngredient.name}
                                        onChange={e => setNewIngredient({ ...newIngredient, name: e.target.value })}
                                        className="flex-1 bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-orange-500"
                                    />
                                    <input
                                        type="text"
                                        placeholder="Unit (e.g. kg)"
                                        required
                                        value={newIngredient.unit_of_measure}
                                        onChange={e => setNewIngredient({ ...newIngredient, unit_of_measure: e.target.value })}
                                        className="w-32 bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-orange-500"
                                    />
                                </div>
                                <div className="flex items-center gap-4">
                                    <input
                                        type="file"
                                        accept="image/*"
                                        onChange={e => setNewIngredient({ ...newIngredient, image: e.target.files[0] })}
                                        className="flex-1 bg-black/20 border border-white/10 rounded-xl px-4 py-2 text-white cursor-pointer file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-orange-500/10 file:text-orange-500 hover:file:bg-orange-500/20 text-sm"
                                    />
                                    <button type="submit" className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-2 rounded-xl transition-colors font-medium h-full min-h-[44px]">Add</button>
                                </div>
                            </form>
                        </div>

                        <div className="glass-dark border border-white/5 rounded-3xl p-6">
                            <h2 className="text-xl font-bold mb-4 text-white">Ingredient Database</h2>
                            <div className="space-y-2 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
                                {filteredIngredients.map(ing => (
                                    <div key={ing.id} className="flex items-center gap-3 p-3 rounded-xl bg-white/5 border border-white/10">
                                        {ing.image ? (
                                            <img src={ing.image} alt={ing.name} className="w-10 h-10 rounded-lg object-cover border border-white/10" />
                                        ) : (
                                            <div className="w-10 h-10 rounded-lg bg-dark-900 border border-white/10 flex items-center justify-center">
                                                <Package size={16} className="text-slate-500" />
                                            </div>
                                        )}
                                        <div className="flex-1 flex justify-between items-center">
                                            <span className="font-semibold">{ing.name}</span>
                                            <span className="text-sm px-2 py-1 bg-black/40 rounded-lg text-slate-400">{ing.unit_of_measure}</span>
                                        </div>
                                    </div>
                                ))}
                                {filteredIngredients.length === 0 && <p className="text-center text-slate-500 py-4">No ingredients match search.</p>}
                            </div>
                        </div>
                    </div>

                    {/* Recipes Column */}
                    <div className="flex flex-col gap-6">
                        <div className="glass-dark border border-white/5 rounded-3xl p-6">
                            <h2 className="text-xl font-bold mb-4 text-white">Map Recipe (BOM)</h2>
                            <form onSubmit={handleCreateRecipe} className="flex flex-col gap-4">
                                <div className="flex flex-col sm:flex-row gap-4">
                                    <select required value={newRecipe.product} onChange={e => setNewRecipe({ ...newRecipe, product: e.target.value })} className="flex-1 bg-black/20 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500">
                                        <option value="" disabled>Select Product...</option>
                                        {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                                    </select>
                                </div>
                                <div className="flex flex-col sm:flex-row gap-4">
                                    <select required value={newRecipe.ingredient} onChange={e => setNewRecipe({ ...newRecipe, ingredient: e.target.value })} className="flex-1 bg-black/20 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500">
                                        <option value="" disabled>Select Ingredient...</option>
                                        {ingredients.map(i => <option key={i.id} value={i.id}>{i.name} ({i.unit_of_measure})</option>)}
                                    </select>
                                    <input
                                        type="number"
                                        step="0.01"
                                        placeholder="Qty"
                                        required
                                        value={newRecipe.quantity_required}
                                        onChange={e => setNewRecipe({ ...newRecipe, quantity_required: e.target.value })}
                                        className="w-24 bg-black/20 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-orange-500"
                                    />
                                    <button type="submit" className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-xl transition-colors font-medium">Link</button>
                                </div>
                            </form>
                        </div>

                        <div className="glass-dark border border-white/5 rounded-3xl p-6">
                            <h2 className="text-xl font-bold mb-4 text-white">Active Product Recipes</h2>
                            <div className="space-y-3 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
                                {filteredRecipesProducts.map(product => (
                                    <div key={product.id} className="bg-white/5 border border-white/10 rounded-xl p-4">
                                        <h3 className="font-bold text-primary-400 mb-3 border-b border-white/10 pb-2">{product.name}</h3>
                                        <div className="space-y-2">
                                            {recipes.filter(r => r.product === product.id).map(recipe => (
                                                <div key={recipe.id} className="flex justify-between items-center text-sm">
                                                    <span className="text-slate-300">• {recipe.quantity_required} {recipe.unit_of_measure} of {recipe.ingredient_name}</span>
                                                    <button onClick={() => handleDeleteRecipe(recipe.id)} className="text-red-400 hover:text-red-300 p-1"><Minus size={14} /></button>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                                {filteredRecipesProducts.length === 0 && <p className="text-center text-slate-500 py-4">No matching recipes mapped.</p>}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { Utensils, QrCode, Zap, Clock, Star, ChefHat, ArrowRight, Store, TrendingUp, Users, Calendar, ChevronDown, CheckCircle2 } from 'lucide-react';
