                </div>
            </section>
        </div>
    );
}

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAppStore } from '../store/useStore';
import { Lock, User, Loader2, Utensils } from 'lucide-react';
import toast from 'react-hot-toast';
import { motion } from 'framer-motion';

export default function Login() {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);

    const login = useAppStore(state => state.login);
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        const toastId = toast.loading('Authenticating...');

        try {
            const role = await login(username, password);
            toast.success(`Welcome back, ${username}!`, { id: toastId });

            if (role === 'CUSTOMER') {
                navigate('/');
            } else {
                navigate('/seller');
            }
        } catch (error) {
            toast.error(error.message || 'Login failed', { id: toastId });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-[80vh] flex items-center justify-center p-4">

            {/* Background decorative elements */}
            <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-primary-500/20 rounded-full blur-[100px] pointer-events-none"></div>
            <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-red-500/10 rounded-full blur-[100px] pointer-events-none"></div>

            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="w-full max-w-md glass-dark rounded-3xl p-8 border border-white/10 shadow-2xl relative z-10"
            >
                <div className="flex flex-col items-center mb-8">
                    <div className="bg-primary-500/10 p-4 rounded-2xl mb-4 border border-primary-500/20">
                        <Utensils size={40} className="text-primary-500" />
                    </div>
                    <h2 className="text-3xl font-bold tracking-tight text-white mb-2">Welcome Back</h2>
                    <p className="text-slate-400 text-center">Sign in to multi-vendor Chapuu Operations.</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-300 ml-1">Username</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                <User size={18} className="text-slate-500" />
                            </div>
                            <input
                                type="text"
                                required
                                value={username}
                                onChange={(e) => setUsername(e.target.value)}
                                className="w-full bg-dark-900 border border-white/10 focus:border-primary-500 focus:ring-1 focus:ring-primary-500 rounded-xl py-3 pl-11 pr-4 text-slate-100 placeholder-slate-600 transition-all outline-none"
                                placeholder="Enter username..."
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-300 ml-1">Password</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                <Lock size={18} className="text-slate-500" />
                            </div>
                            <input
                                type="password"
                                required
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                className="w-full bg-dark-900 border border-white/10 focus:border-primary-500 focus:ring-1 focus:ring-primary-500 rounded-xl py-3 pl-11 pr-4 text-slate-100 placeholder-slate-600 transition-all outline-none"
                                placeholder="••••••••"
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full mt-8 bg-gradient-to-r from-primary-500 to-primary-600 hover:from-primary-400 hover:to-primary-500 text-dark-950 font-bold py-3.5 rounded-xl transition-all shadow-lg shadow-primary-500/20 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 transform hover:-translate-y-0.5 active:translate-y-0"
                    >
                        {loading ? <Loader2 className="animate-spin" size={20} /> : "Sign In securely"}
                    </button>
                </form>

                <div className="mt-8 pt-6 border-t border-white/10 text-center">
                    <p className="text-sm text-slate-500 mb-2">Demo Accounts:</p>
                    <div className="flex justify-center gap-4 text-xs font-medium">
                        <span className="bg-white/5 px-2 py-1 rounded text-primary-400">customer1</span>
                        <span className="bg-white/5 px-2 py-1 rounded text-green-400">seller1</span>
                        <span className="bg-white/5 px-2 py-1 rounded text-red-400">admin</span>
                    </div>
                </div>

                <div className="mt-6 text-center">
                    <p className="text-slate-400">
                        New to Chapuu?{' '}
                        <Link to="/register" className="text-primary-400 hover:text-primary-300 font-semibold transition-colors">
                            Create an account
                        </Link>
                    </p>
                </div>
            </motion.div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import apiClient from '../api/client';
import { motion, AnimatePresence } from 'framer-motion';
import { ChefHat, CheckCircle2, Clock, CreditCard, ShoppingBag, ArrowLeft, RefreshCw } from 'lucide-react';
import toast from 'react-hot-toast';

export default function OrderTracker() {
    const { id } = useParams();
    const [order, setOrder] = useState(null);
    const [loading, setLoading] = useState(true);

    // Review State
    const [showReviewModal, setShowReviewModal] = useState(false);
    const [rating, setRating] = useState(0);
    const [comment, setComment] = useState('');
    const [reviewSubmitted, setReviewSubmitted] = useState(false);

    const fetchOrder = () => {
        apiClient.get(`/orders/${id}/`)
            .then(res => {
                setOrder(res.data);
                setLoading(false);
                if (res.data.state === 'COMPLETED' && !reviewSubmitted) {
                    setShowReviewModal(true);
                }
            })
            .catch(err => {
                console.error("Could not fetch order", err);
                setLoading(false);
            });
    }

    const submitReview = () => {
        if (rating === 0) {
            toast.error("Please provide a star rating!");
            return;
        }
        apiClient.post('/reviews/', {
            store: order.store,
            rating: rating,
            comment: comment
        }).then(() => {
            toast.success("Review submitted!");
            setReviewSubmitted(true);
            setShowReviewModal(false);
        }).catch(err => {
            console.error("Failed to submit review", err);
            toast.error("Could not submit review.");
        });
    }

    useEffect(() => {
        fetchOrder();
        const interval = setInterval(fetchOrder, 10000);
        return () => clearInterval(interval);
    }, [id]);

    if (loading) {
        return (
            <div className="flex justify-center items-center h-[calc(100vh-200px)]">
                <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary-500"></div>
            </div>
        );
    }

    if (!order) {
        return <div className="text-center py-20 text-white">Order not found.</div>;
    }

    const stateFlow = ['CREATED', 'AWAITING_PAYMENT', 'PAID', 'QUEUED', 'PREPARING', 'READY', 'COMPLETED'];
    const currentStateIndex = stateFlow.indexOf(order.state);

    const getIcon = (state) => {
        switch (state) {
            case 'AWAITING_PAYMENT': return <CreditCard size={24} />;
            case 'QUEUED': return <Clock size={24} />;
            case 'PREPARING': return <ChefHat size={24} />;
            case 'READY': return <CheckCircle2 size={24} />;
            case 'COMPLETED': return <ShoppingBag size={24} />;
            default: return <Clock size={24} />;
        }
    };

    const getStatusText = (state) => {
        switch (state) {
            case 'AWAITING_PAYMENT': return 'Awaiting Payment Verification';
            case 'PAID':
            case 'QUEUED': return 'Received & In Queue';
            case 'PREPARING': return 'Kitchen is Preparing';
            case 'READY': return 'Ready for Pickup / Service';
            case 'COMPLETED': return 'Completed';
            default: return 'Processing';
        }
    };

    const displayStates = ['AWAITING_PAYMENT', 'QUEUED', 'PREPARING', 'READY'];

    return (
        <div className="w-full max-w-3xl mx-auto py-8 px-4">

            <div className="flex items-center gap-4 mb-8">
                <Link to="/menu" className="p-2 bg-white/5 hover:bg-white/10 rounded-xl transition-colors text-slate-400 hover:text-white">
                    <ArrowLeft size={20} />
                </Link>
                <div>
                    <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                        Track Order #{order.id}
                        <button onClick={fetchOrder} className="text-slate-500 hover:text-primary-500 transition-colors" title="Refresh">
                            <RefreshCw size={20} />
                        </button>
                    </h1>
                    <p className="text-slate-400 text-sm mt-1">{order.store_name || `From Store #${order.store}`}</p>
                </div>
            </div>

            <div className="glass-dark border border-white/10 rounded-3xl p-8 mb-8 shadow-2xl">

                <h3 className="text-lg font-bold text-white mb-8 border-b border-white/5 pb-4">Live Status</h3>

                {/* Progress Bar & Steps */}
                <div className="relative flex flex-col md:flex-row justify-between gap-8 md:gap-0">
                    {/* Background Line */}
                    <div className="absolute left-[39px] md:left-0 top-0 md:top-[39px] bottom-0 md:bottom-auto w-1 md:w-full h-full md:h-1 bg-white/10 -z-10 rounded"></div>

                    {/* Progress Indicator Line */}
                    <div className="absolute left-[39px] md:left-0 top-0 md:top-[39px] bottom-0 md:bottom-auto w-1 md:h-1 bg-primary-500 transition-all duration-1000 -z-10 rounded shadow-[0_0_15px_rgba(249,115,22,0.5)]"
                        style={{
                            width: window.innerWidth >= 768 ? `${Math.max(0, (displayStates.indexOf(order.state === 'PAID' ? 'QUEUED' : order.state) / (displayStates.length - 1)) * 100)}%` : '4px',
                            height: window.innerWidth < 768 ? `${Math.max(0, (displayStates.indexOf(order.state === 'PAID' ? 'QUEUED' : order.state) / (displayStates.length - 1)) * 100)}%` : '4px'
                        }}
                    ></div>

                    {displayStates.map((state, idx) => {
                        const targetStateIndex = stateFlow.indexOf(state);
                        // PAID is essentially QUEUED visually
                        const activeIndex = order.state === 'PAID' ? stateFlow.indexOf('QUEUED') : currentStateIndex;

                        const isPast = activeIndex > targetStateIndex;
                        const isCurrent = activeIndex === targetStateIndex;
                        const isFuture = activeIndex < targetStateIndex;

                        return (
                            <div key={state} className={`flex md:flex-col items-center gap-6 md:gap-4 flex-1 ${isCurrent ? 'md:-mt-2 opacity-100' : 'opacity-50'}`}>
                                <motion.div
                                    animate={{ scale: isCurrent ? 1.2 : 1 }}
                                    className={`w-20 h-20 rounded-full flex items-center justify-center shrink-0 border-4 shadow-xl z-10 transition-colors duration-500
                                        ${isPast ? 'bg-primary-500 border-primary-600 text-dark-900 shadow-primary-500/30' :
                                            isCurrent ? 'bg-dark-900 border-primary-500 text-primary-500 shadow-primary-500/50' :
                                                'bg-dark-800 border-white/10 text-slate-500'}`}
                                >
                                    {getIcon(state)}
                                </motion.div>

                                <div className="text-left md:text-center mt-2">
                                    <h4 className={`font-bold transition-colors ${isCurrent ? 'text-primary-400 text-lg' : isPast ? 'text-white' : 'text-slate-500'}`}>
                                        {getStatusText(state)}
                                    </h4>
                                    {isCurrent && (
                                        <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-xs text-slate-400 mt-1">
                                            {state === 'AWAITING_PAYMENT' && "Waiting for restaurant to confirm payment..."}
                                            {state === 'QUEUED' && "Your ticket is on the board!"}
                                            {state === 'PREPARING' && "Chef is actively cooking!"}
                                            {state === 'READY' && "Enjoy your meal!"}
                                        </motion.p>
                                    )}
                                </div>
                            </div>
                        )
                    })}
                </div>
            </div>

            {/* Order Items summary */}
            <div className="glass-dark border border-white/10 rounded-3xl p-6 md:p-8">
                <h3 className="text-lg font-bold text-white mb-6 border-b border-white/5 pb-4">Order Details</h3>

                <div className="space-y-4 mb-6">
                    {order.items.map(item => (
                        <div key={item.id} className="flex justify-between items-center text-slate-300 bg-dark-900/50 p-3 rounded-xl border border-white/5">
                            <div>
                                <span className="font-bold text-white w-8 inline-block">{item.quantity}x</span>
                                {item.product.name}
                            </div>
                            <span className="text-primary-400 font-semibold">${item.unit_price}</span>
                        </div>
                    ))}
                </div>

                <div className="pt-4 border-t border-white/10 mt-4 text-sm text-slate-400 flex flex-col md:flex-row justify-between items-start md:items-center gap-2">
                    <p>Placed: {new Date(order.created_at).toLocaleDateString()} at {new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                    {order.customer_phone && <p>Contact: {order.customer_phone}</p>}
                </div>

                <div className="pt-4 border-t border-white/10 flex justify-between items-center mt-2">
                    <span className="text-slate-400 font-medium">Total Paid</span>
                    <span className="text-2xl font-bold tracking-tight text-white">${order.total_amount}</span>
                </div>
            </div>

            {/* Review Modal */}
            <AnimatePresence>
                {showReviewModal && !reviewSubmitted && (order.state === 'COMPLETED' || order.state === 'READY') && (
                    <motion.div
                        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                        className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-dark-950/80 backdrop-blur-sm"
                    >
                        <motion.div
                            initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, y: 20 }}
                            className="bg-dark-900 border border-white/10 rounded-3xl p-8 max-w-md w-full shadow-2xl relative"
                        >
                            <h2 className="text-2xl font-bold text-white mb-2 text-center">Rate Your Experience</h2>
                            <p className="text-slate-400 text-center text-sm mb-6">How was your order from {order.store_name || `Store #${order.store}`}?</p>

                            <div className="flex justify-center gap-2 mb-6">
                                {[1, 2, 3, 4, 5].map(star => (
                                    <button
                                        key={star}
                                        onClick={() => setRating(star)}
                                        className={`p-2 transition-transform hover:scale-110 ${rating >= star ? 'text-yellow-400' : 'text-slate-600'}`}
                                    >
                                        <svg className="w-10 h-10 fill-current" viewBox="0 0 24 24">
                                            <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
                                        </svg>
                                    </button>
                                ))}
                            </div>

                            <textarea
                                value={comment}
                                onChange={(e) => setComment(e.target.value)}
                                placeholder="Leave a comment (optional)..."
                                className="w-full bg-dark-950 border border-white/10 rounded-xl p-4 text-slate-200 focus:border-primary-500 transition-all resize-none mb-6 h-24"
                            ></textarea>

                            <div className="flex gap-4">
                                <button
                                    onClick={() => setShowReviewModal(false)}
                                    className="flex-1 py-3 text-slate-400 hover:text-white transition-colors font-medium"
                                >
                                    Dismiss
                                </button>
                                <button
                                    onClick={submitReview}
                                    className="flex-1 bg-primary-500 hover:bg-primary-400 text-dark-900 font-bold py-3 rounded-xl shadow-[0_0_20px_rgba(249,115,22,0.3)] transition-all transform hover:-translate-y-1"
                                >
                                    Submit Review
                                </button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>

        </div>
    );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Utensils, CheckCircle, Clock } from 'lucide-react';
import apiClient from '../api/client';

export default function PublicDisplay() {
    const { storeId } = useParams();
    const navigate = useNavigate();

    const [storeName, setStoreName] = useState('');
    const [orders, setOrders] = useState([]);
    const [ads, setAds] = useState([]);
    const [featuredProducts, setFeaturedProducts] = useState([]);

    // Cycle state: 0 = Queue Board, 1 = Ad/Featured Board
    const [viewMode, setViewMode] = useState(0);
    const [currentAdIndex, setCurrentAdIndex] = useState(0);

    const fetchData = async () => {
        try {
            if (storeId) {
                const storeRes = await apiClient.get(`/stores/${storeId}/`);
                setStoreName(storeRes.data.name);
            }

            // Fetch live KDS orders for the store
            const orderRes = await apiClient.get(storeId ? `/orders/?store=${storeId}` : '/orders/');
            // Only show active kitchen orders (exclude delivery/cart states)
            const activeOrders = orderRes.data.filter(o => ['QUEUED', 'PREPARING', 'READY'].includes(o.state));
            setOrders(activeOrders);

            // Fetch ads 
            const adsRes = await apiClient.get(storeId ? `/ads/?store=${storeId}` : '/ads/');
            setAds(adsRes.data);

            // Fetch featured products (just taking top 4 for now)
            const prodRes = await apiClient.get(storeId ? `/products/?store=${storeId}` : '/products/');
            if (prodRes.data.length > 0) {
                // simple deterministic shuffle / slice
                setFeaturedProducts(prodRes.data.slice(0, 4));
            }

        } catch (error) {
            console.error("Failed fetching TV data:", error);
        }
    };

    useEffect(() => {
        fetchData();
        const dataInterval = setInterval(fetchData, 5000); // 5 sec Polling

        // Cycle View Logic (10 seconds order board, 10 seconds ad board)
        const viewInterval = setInterval(() => {
            setViewMode(prev => {
                if (prev === 0 && ads.length > 0) {
                    // Switch to ad mode, increment ad
                    setCurrentAdIndex(idx => (idx + 1) % ads.length);
                    return 1;
                }
                return 0;
            });
        }, 12000);

        return () => {
            clearInterval(dataInterval);
            clearInterval(viewInterval);
        };
    }, [storeId, ads.length]);

    const queued = orders.filter(o => o.state === 'QUEUED').slice(0, 6);
    const preparing = orders.filter(o => o.state === 'PREPARING').slice(0, 6);
    const ready = orders.filter(o => o.state === 'READY').reverse();

    return (
        <div className="w-full h-screen bg-dark-950 text-white overflow-hidden flex flex-col relative select-none">
            {/* Header / Brand Bar */}
            <div className="h-20 bg-dark-900 border-b border-white/5 flex items-center justify-between px-8 shadow-xl z-20">
                <div className="flex items-center gap-4">
                    <motion.div
                        animate={{ rotate: 360 }}
                        transition={{ repeat: Infinity, duration: 20, ease: "linear" }}
                        className="bg-primary-500/20 p-3 rounded-2xl"
                    >
                        <Utensils className="text-primary-500" size={32} />
                    </motion.div>
                    <div>
                        <h1 className="text-3xl font-black tracking-tight">{storeName || 'Global Queue'}</h1>
                        <p className="text-slate-400 font-medium tracking-widest uppercase text-sm">Live Order Status</p>
                    </div>
                </div>

                <div className="text-right">
                    <motion.div
                        animate={{ opacity: [0.5, 1, 0.5] }}
                        transition={{ repeat: Infinity, duration: 2 }}
                        className="flex items-center gap-2 text-green-400 font-bold text-xl"
                    >
                        <div className="w-3 h-3 bg-green-500 rounded-full"></div>
                        LIVE UPDATE
                    </motion.div>
                </div>
            </div>

            {/* Main Stage */}
            <div className="flex-1 relative">
                <AnimatePresence mode="wait">
                    {viewMode === 0 ? (
                        <motion.div
                            key="queue-board"
                            initial={{ opacity: 0, x: -50 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 50 }}
                            className="absolute inset-0 grid grid-cols-3 gap-8 p-8"
                        >
                            {/* QUEUED COLUMN */}
                            <div className="glass flex flex-col rounded-3xl overflow-hidden border border-white/5">
                                <div className="bg-slate-800/50 py-4 px-6 border-b border-white/5 flex items-center gap-3">
                                    <Clock size={28} className="text-slate-400" />
                                    <h2 className="text-2xl font-bold uppercase tracking-widest text-slate-300">Queued</h2>
                                </div>
                                <div className="flex-1 p-6 space-y-4">
                                    {queued.map(o => (
                                        <div key={o.id} className="bg-dark-900/50 p-6 rounded-2xl border border-white/5 shadow-lg flex justify-between items-center">
                                            <span className="text-4xl font-black font-mono tracking-tighter text-slate-400">#{o.id}</span>
                                        </div>
                                    ))}
                                    {queued.length === 0 && <p className="text-slate-600 text-center mt-10 text-xl font-bold">No orders queued</p>}
                                </div>
                            </div>

                            {/* PREPARING COLUMN */}
                            <div className="glass flex flex-col rounded-3xl overflow-hidden border border-white/5">
                                <div className="bg-orange-500/10 py-4 px-6 border-b border-orange-500/20 flex items-center gap-3">
                                    <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 4, ease: "linear" }}>
                                        <Utensils size={28} className="text-orange-400" />
                                    </motion.div>
                                    <h2 className="text-2xl font-bold uppercase tracking-widest text-orange-400">Cooking</h2>
                                </div>
                                <div className="flex-1 p-6 space-y-4">
                                    {preparing.map(o => (
                                        <motion.div
                                            key={o.id}
                                            initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                                            className="bg-orange-500/5 p-6 rounded-2xl border border-orange-500/20 shadow-lg flex justify-between items-center"
                                        >
                                            <span className="text-4xl font-black font-mono tracking-tighter text-orange-300">#{o.id}</span>
                                            <span className="text-sm font-bold text-orange-500/60 uppercase tracking-widest animate-pulse">Prep</span>
                                        </motion.div>
                                    ))}
                                    {preparing.length === 0 && <p className="text-slate-600 text-center mt-10 text-xl font-bold">Kitchen is clear</p>}
                                </div>
                            </div>

                            {/* READY COLUMN */}
                            <div className="glass flex flex-col rounded-3xl overflow-hidden shadow-[0_0_50px_rgba(34,197,94,0.1)] border-t-[6px] border-t-green-500">
                                <div className="bg-green-500/10 py-6 px-6 border-b border-green-500/20 flex items-center gap-3 justify-center">
                                    <CheckCircle size={40} className="text-green-500" />
                                    <h2 className="text-4xl font-black uppercase tracking-widest text-green-400">Please Collect</h2>
                                </div>
                                <div className="flex-1 p-6 flex flex-wrap gap-4 align-start content-start">
                                    {ready.map(o => (
                                        <motion.div
                                            key={o.id}
                                            initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                                            className="bg-green-500 w-[47%] py-8 rounded-2xl shadow-[0_10px_30px_rgba(34,197,94,0.3)] flex justify-center items-center"
                                        >
                                            <span className="text-5xl font-black font-mono tracking-tighter text-dark-900 drop-shadow-md">#{o.id}</span>
                                        </motion.div>
                                    ))}
                                    {ready.length === 0 && <p className="text-slate-600 text-center w-full mt-10 text-2xl font-bold">No completed orders</p>}
                                </div>
                            </div>

                        </motion.div>
                    ) : (
                        <motion.div
                            key={`ad-board-${currentAdIndex}`}
                            initial={{ opacity: 0, scale: 1.05 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0 }}
                            transition={{ duration: 1 }}
                            className="absolute inset-0 flex items-center justify-center p-12"
                        >
                            {ads.length > 0 && ads[currentAdIndex].media ? (
                                <div className="w-full h-full relative rounded-[3rem] overflow-hidden shadow-2xl border border-white/10">
                                    <div className="absolute inset-0 bg-gradient-to-t from-dark-950 via-transparent to-transparent z-10"></div>
                                    {ads[currentAdIndex].media.endsWith('.mp4') ? (
                                        <video src={ads[currentAdIndex].media} autoPlay muted loop className="w-full h-full object-cover" />
                                    ) : (
                                        <img src={ads[currentAdIndex].media} alt="Ad" className="w-full h-full object-cover" />
                                    )}
                                    <div className="absolute bottom-12 left-12 z-20">
                                        <h2 className="text-6xl font-black drop-shadow-2xl">{ads[currentAdIndex].title}</h2>
                                    </div>
                                </div>
                            ) : (
                                <div className="text-4xl font-bold text-slate-500">Promotions Array Empty</div>
                            )}
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Ticker / Footer */}
            <div className="h-12 bg-primary-600 flex items-center overflow-hidden z-20">
                <motion.div
                    animate={{ x: ["100%", "-100%"] }}
                    transition={{ repeat: Infinity, duration: 25, ease: "linear" }}
                    className="whitespace-nowrap flex gap-12 font-bold tracking-widest text-lg drop-shadow-md text-dark-900"
                >
                    {featuredProducts.length > 0 ? featuredProducts.map((p, i) => (
                        <span key={i}>★ TRY OUR {p.name.toUpperCase()} FOR ${p.price} ★</span>
                    )) : (
                        <span>★ ORDER AT THE COUNTER OR SCAN YOUR TABLE'S QR CODE ★</span>
                    )}
                </motion.div>
            </div>

        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Calendar as CalendarIcon, Clock, Users, MapPin, CheckCircle } from 'lucide-react';
import toast from 'react-hot-toast';
import apiClient from '../api/client';
import { useNavigate } from 'react-router-dom';
import { useAppStore } from '../store/useStore';

export default function ReservationForm() {
    const [stores, setStores] = useState([]);
    const [selectedStore, setSelectedStore] = useState('');

    const [date, setDate] = useState('');
    const [time, setTime] = useState('');
    const [guests, setGuests] = useState(2);
    const [duration, setDuration] = useState(60);

    const [isSubmitting, setIsSubmitting] = useState(false);
    const [confirmedRes, setConfirmedRes] = useState(null);

    useEffect(() => {
        apiClient.get('/stores/')
            .then(res => {
                setStores(res.data);
                if (res.data.length > 0) setSelectedStore(res.data[0].id);
            })
            .catch(err => console.error(err));
    }, []);

    const handleReserve = (e) => {
        e.preventDefault();
        if (!date || !time) {
            toast.error("Please select a date and time!");
            return;
        }

        if (!selectedStore) {
            toast.error("No store available to select!");
            return;
        }

        const isoTimeStr = `${date}T${time}:00Z`; // Construct ISO datetime. Assuming simple local->UTC overlap for mockup

        setIsSubmitting(true);
        const toastId = toast.loading("Checking availability...");

        apiClient.post('/reservations/', {
            store: selectedStore,
            reservation_time: isoTimeStr,
            duration_minutes: duration,
            guest_count: guests
        }).then(res => {
            toast.success("Table Confirmed!", { id: toastId });
            setConfirmedRes(res.data);
            setIsSubmitting(false);
        }).catch(err => {
            const errorMsg = err.response?.data?.error || "Booking failed.";
            toast.error(`Unavailable: ${errorMsg}`, { id: toastId });
            setIsSubmitting(false);
        });
    };

    const navigate = useNavigate();

    const handleSkipFood = () => {
        setConfirmedRes(null);
        navigate('/');
    };

    const handlePreOrderFood = () => {
        // Global state for reservation could be set here, but URL params/state is simpler.
        // Zustand could also hold this: useAppStore.getState().setActiveReservation(confirmedRes.id)
        useAppStore.setState({ activeReservation: confirmedRes.id, activeStore: selectedStore });
        navigate('/menu');
    };

    if (confirmedRes) {
        return (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex justify-center items-center py-10 lg:py-20">
                <div className="glass-dark border border-green-500/20 p-8 md:p-10 rounded-3xl max-w-lg w-full text-center relative overflow-hidden shadow-2xl shadow-green-500/10">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-green-500/10 rounded-full blur-3xl pointer-events-none"></div>
                    <CheckCircle className="w-20 h-20 text-green-500 mx-auto mb-6 relative z-10" />
                    <h2 className="text-3xl font-black mb-4 z-10 text-white relative">Table Confirmed!</h2>
                    <p className="text-slate-300 mb-8 z-10 relative">Your table is secured. Would you like to order food now so it's ready when you arrive?</p>

                    <div className="bg-dark-900/50 z-10 relative border border-white/5 rounded-2xl p-6 text-left mb-8 space-y-4 shadow-inner">
                        <div className="flex justify-between items-center border-b border-white/5 pb-3">
                            <span className="text-slate-400 font-medium">Table</span>
                            <strong className="text-white text-lg">{confirmedRes.table_number || 'Auto-Assigned'}</strong>
                        </div>
                        <div className="flex justify-between items-center border-b border-white/5 pb-3">
                            <span className="text-slate-400 font-medium">Date & Time</span>
                            <strong className="text-white">{new Date(confirmedRes.reservation_time).toLocaleString(undefined, { weekday: 'short', month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' })}</strong>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-slate-400 font-medium">Guests</span>
                            <strong className="text-white flex items-center gap-2"><Users size={16} className="text-primary-500" /> {confirmedRes.guest_count} People</strong>
                        </div>
                    </div>

                    <div className="flex flex-col gap-4 relative z-10">
                        <button
                            onClick={handlePreOrderFood}
                            className="w-full bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-400 hover:to-emerald-500 text-dark-950 py-4 rounded-xl transition-all font-bold text-lg shadow-lg shadow-green-500/25 flex items-center justify-center gap-2 transform hover:-translate-y-1"
                        >
                            <Utensils size={20} /> Pre-order Food for the Table
                        </button>
                        <button
                            onClick={handleSkipFood}
                            className="w-full bg-white/5 border border-white/10 hover:bg-white/10 text-white py-4 rounded-xl transition-colors font-medium"
                        >
                            I'm Done (Skip Food)
                        </button>
                    </div>
                </div>
            </motion.div>
        );
    }

    return (
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="max-w-xl mx-auto py-10">
            <div className="glass-dark border border-white/5 p-8 rounded-3xl shadow-xl">
                <h2 className="text-2xl font-bold mb-6 flex items-center gap-3">
                    <CalendarIcon className="text-primary-500" />
                    Reserve a Table
                </h2>

                <form onSubmit={handleReserve} className="space-y-6">
                    <div>
                        <label className="block text-sm font-medium text-slate-400 mb-2 flex items-center gap-2"><MapPin size={16} /> Select Location</label>
                        <select
                            value={selectedStore}
                            onChange={(e) => setSelectedStore(e.target.value)}
                            className="w-full bg-dark-900 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-primary-500 appearance-none"
                        >
                            {stores.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                        </select>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-400 mb-2 flex items-center gap-2"><CalendarIcon size={16} /> Date</label>
                            <input
                                type="date"
                                value={date}
                                onChange={(e) => setDate(e.target.value)}
                                className="w-full bg-dark-900 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-primary-500 text-white [color-scheme:dark]"
                                required
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-400 mb-2 flex items-center gap-2"><Clock size={16} /> Time</label>
                            <input
                                type="time"
                                value={time}
                                onChange={(e) => setTime(e.target.value)}
                                className="w-full bg-dark-900 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-primary-500 text-white [color-scheme:dark]"
                                required
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-400 mb-2 flex items-center gap-2"><Users size={16} /> Party Size</label>
                            <input
                                type="number"
                                min="1" max="20"
                                value={guests}
                                onChange={(e) => setGuests(e.target.value)}
                                className="w-full bg-dark-900 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-primary-500 text-white"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-400 mb-2 text-transparent select-none">Duration</label>
                            <select
                                value={duration}
                                onChange={(e) => setDuration(e.target.value)}
                                className="w-full bg-dark-900 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-primary-500 appearance-none"
                            >
                                <option value={30}>30 Minutes</option>
                                <option value={60}>1 Hour</option>
                                <option value={90}>1.5 Hours</option>
                                <option value={120}>2 Hours</option>
                            </select>
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={isSubmitting}
                        className="w-full mt-4 bg-primary-600 hover:bg-primary-500 text-white font-bold py-4 rounded-xl shadow-lg transition-transform hover:scale-105 active:scale-95 disabled:opacity-50 disabled:hover:scale-100"
                    >
                        {isSubmitting ? 'Checking...' : 'Confirm Booking'}
                    </button>
                </form>
            </div>
        </motion.div>
    );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Users, Clock, Check, X, Calendar as CalendarIcon, LogIn } from 'lucide-react';
import toast from 'react-hot-toast';
import apiClient from '../api/client';

export default function ReservationManager() {
    const [reservations, setReservations] = useState([]);

    const fetchReservations = () => {
        apiClient.get('/reservations/')
            .then(res => setReservations(res.data))
            .catch(err => toast.error("Failed to load reservations."));
    }

    useEffect(() => {
        fetchReservations();
        const interval = setInterval(fetchReservations, 15000);
        return () => clearInterval(interval);
    }, []);

    const handleConfirm = (id) => {
        apiClient.post(`/reservations/${id}/confirm/`)
            .then(() => {
                toast.success("Reservation confirmed.");
                fetchReservations();
            }).catch(err => toast.error("Error confirming."));
    }

    const handleCheckIn = (id) => {
        apiClient.post(`/reservations/${id}/check_in/`)
            .then(() => {
                toast.success("Customer checked in. Table active!");
                fetchReservations();
            }).catch(err => toast.error("Check-in failed."));
    }

    const pending = reservations.filter(r => r.status === 'PENDING');
    const upcoming = reservations.filter(r => r.status === 'CONFIRMED');
    const active = reservations.filter(r => r.status === 'ACTIVE');

    const renderCard = (res) => (
        <motion.div layout initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} key={res.id} className="glass-dark border border-white/5 rounded-2xl p-5 mb-4 shadow-sm hover:border-white/10 transition-colors">
            <div className="flex justify-between items-start mb-3">
                <div>
                    <h3 className="font-bold text-lg">{res.customer_name}</h3>
                    <p className="text-sm text-primary-400">Table {res.table_number || 'TBD'}</p>
                </div>
                <div className="flex items-center gap-1 bg-white/5 px-2 py-1 rounded-md text-slate-300 text-xs font-semibold">
                    <Users size={14} /> {res.guest_count}
                </div>
            </div>

            <div className="flex items-center gap-2 text-sm text-slate-400 mb-5 pb-4 border-b border-white/5">
                <Clock size={16} /> {new Date(res.reservation_time).toLocaleString()}
            </div>

            <div className="flex gap-2">
                {res.status === 'PENDING' && (
                    <button onClick={() => handleConfirm(res.id)} className="flex-1 bg-primary-600/20 hover:bg-primary-600/40 text-primary-400 py-2 rounded-lg text-sm font-medium transition-colors flex justify-center items-center gap-2">
                        <Check size={16} /> Confirm
                    </button>
                )}
                {res.status === 'CONFIRMED' && (
                    <button onClick={() => handleCheckIn(res.id)} className="flex-1 bg-green-500/20 hover:bg-green-500/40 text-green-400 py-2 rounded-lg text-sm font-medium transition-colors flex justify-center items-center gap-2">
                        <LogIn size={16} /> Check-In
                    </button>
                )}
                {(res.status === 'PENDING' || res.status === 'CONFIRMED') && (
                    <button className="px-4 bg-red-500/10 hover:bg-red-500/20 text-red-400 rounded-lg transition-colors flex items-center justify-center">
                        <X size={18} />
                    </button>
                )}
                {res.status === 'ACTIVE' && (
                    <div className="w-full text-center py-2 text-green-500 font-semibold bg-green-500/10 rounded-lg">
                        Dining...
                    </div>
                )}
            </div>
        </motion.div>
    );

    return (
        <div className="w-full min-h-screen py-6 px-2">
            <div className="flex items-center justify-between mb-8">
                <h1 className="text-3xl font-bold flex items-center gap-3"><CalendarIcon className="text-indigo-500" /> Host Stand</h1>
                <div className="text-sm text-slate-500">Live updating...</div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

                {/* Column: Pending */}
                <div className="flex flex-col bg-black/20 rounded-3xl p-4 overflow-hidden h-[60vh] md:h-[80vh]">
                    <h2 className="text-lg font-semibold text-slate-400 mb-4 sticky top-0 px-2">Pending Requests <span className="ml-2 bg-white/10 text-xs px-2 py-0.5 rounded-full">{pending.length}</span></h2>
                    <div className="flex-1 overflow-y-auto px-2 custom-scrollbar pb-10">
                        {pending.length === 0 ? <p className="text-slate-600 text-sm text-center py-10">No pending requests</p> : pending.map(renderCard)}
                    </div>
                </div>

                {/* Column: Upcoming */}
                <div className="flex flex-col bg-black/20 rounded-3xl p-4 overflow-hidden h-[60vh] md:h-[80vh]">
                    <h2 className="text-lg font-semibold text-primary-400 mb-4 sticky top-0 px-2">Confirmed Upcoming <span className="ml-2 bg-primary-500/20 text-primary-400 text-xs px-2 py-0.5 rounded-full">{upcoming.length}</span></h2>
                    <div className="flex-1 overflow-y-auto px-2 custom-scrollbar pb-10">
                        {upcoming.length === 0 ? <p className="text-slate-600 text-sm text-center py-10">No upcoming reservations</p> : upcoming.map(renderCard)}
                    </div>
                </div>

                {/* Column: Active (Seated) */}
                <div className="flex flex-col bg-black/20 rounded-3xl p-4 overflow-hidden h-[60vh] md:h-[80vh]">
                    <h2 className="text-lg font-semibold text-green-400 mb-4 sticky top-0 px-2">Currently Seated <span className="ml-2 bg-green-500/20 text-green-500 text-xs px-2 py-0.5 rounded-full">{active.length}</span></h2>
                    <div className="flex-1 overflow-y-auto px-2 custom-scrollbar pb-10">
                        {active.length === 0 ? <p className="text-slate-600 text-sm text-center py-10">No tables active</p> : active.map(renderCard)}
                    </div>
                </div>

            </div>
        </div>
    );
}

import { useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import apiClient from '../api/client';
import { useAppStore } from '../store/useStore';
import toast from 'react-hot-toast';

export default function ScanHandler() {
    const [searchParams] = useSearchParams();
    const storeId = searchParams.get('store_id');
    const tableId = searchParams.get('table_id');
    const navigate = useNavigate();
    const { setSelectedStore } = useAppStore();

    useEffect(() => {
        if (!storeId || !tableId) {
            toast.error("Invalid QR code.");
            navigate('/stores');
            return;
        }

        apiClient.get(`/stores/${storeId}/`)
            .then(res => {
                setSelectedStore(res.data);
                // We'll pass the table_id via state to the menu, so Checkout can pick it up
                // Or we can save it to localStorage so Checkout knows which table we are at.
                localStorage.setItem('scanned_table_id', tableId);
                toast.success(`Welcome to ${res.data.name}!`);
                navigate('/menu');
            })
            .catch(err => {
                toast.error("Could not load restaurant from QR code.");
                navigate('/stores');
            });
    }, [storeId, tableId, navigate, setSelectedStore]);

    return (
        <div className="flex justify-center flex-col items-center h-[calc(100vh-200px)]">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary-500 mb-4"></div>
            <p className="text-slate-400">Loading your table...</p>
        </div>
    );
}

import { useState, useEffect } from 'react';
import apiClient from '../api/client';
import { motion, AnimatePresence } from 'framer-motion';
import { ChefHat, CheckCircle2, Clock, ListOrdered, Utensils, CreditCard, Play, SquareTerminal, Star, MessageSquare } from 'lucide-react';
import toast from 'react-hot-toast';
import { useAppStore } from '../store/useStore';
export default function SellerDashboard() {
    const [orders, setOrders] = useState([]);
    const [queueSize, setQueueSize] = useState(0);
    const [loading, setLoading] = useState(true);
    const { userRole, clearAuth } = useAppStore();

    // POS Override State
    const [showPOSModal, setShowPOSModal] = useState(false);
    const [posProducts, setPosProducts] = useState([]);
    const [posCart, setPosCart] = useState([]);
    const [posCustomerName, setPosCustomerName] = useState('');

    // Dashboard View State
    const [activeView, setActiveView] = useState('KITCHEN'); // 'KITCHEN' or 'REVIEWS'
    const [reviews, setReviews] = useState([]);

    const fetchDashboard = () => {
        apiClient.get('/orders/')
            .then(res => {
                setOrders(res.data);
                setLoading(false);
            })
            .catch(err => {
                toast.error("Error syncing live dashboard");
                setLoading(false);
            });

        apiClient.get('/stores/1/kitchen_queue/')
            .then(res => setQueueSize(res.data.queue_size))
            .catch(console.error);

        apiClient.get('/products/')
            .then(res => setPosProducts(res.data))
            .catch(console.error);

        // Fetching reviews for store ID 1 (Assuming active store session)
        apiClient.get('/stores/1/reviews/')
            .then(res => setReviews(res.data))
            .catch(console.error);
    }

    const markItemReady = (orderId, itemId) => {
        const toastId = toast.loading('Marking item ready...');
        apiClient.post(`/orders/${orderId}/items/${itemId}/ready/`)
            .then(() => {
                toast.success('Kitchen item completed!', { id: toastId });
                fetchDashboard();
            })
            .catch(err => toast.error("Error updating item: " + err.message, { id: toastId }));
    }

    const advanceOrderState = (orderId, newState) => {
        const toastId = toast.loading('Updating order...');
        apiClient.post(`/orders/${orderId}/advance_state/`, { state: newState })
            .then(() => {
                toast.success('Order advanced!', { id: toastId });
                fetchDashboard();
            })
            .catch(err => toast.error("Error updating order: " + err.message, { id: toastId }));
    }

    useEffect(() => {
        fetchDashboard();
        const interval = setInterval(fetchDashboard, 5000);
        return () => clearInterval(interval);
    }, []);

    const activeOrders = orders.filter(o => o.state !== 'COMPLETED' && o.state !== 'CANCELLED' && o.state !== 'CREATED');
    const awaitingPaymentOrders = activeOrders.filter(o => o.state === 'AWAITING_PAYMENT');
    const queuedOrders = activeOrders.filter(o => o.state === 'QUEUED' || o.state === 'PAID');
    const preparingOrders = activeOrders.filter(o => o.state === 'PREPARING');
    const readyOrders = activeOrders.filter(o => o.state === 'READY');

    return (
        <div className="w-full min-h-screen flex flex-col pt-4 pb-8 overflow-y-auto overflow-x-hidden">

            {/* POS Header Actions */}
            <div className="flex justify-between items-center mb-6">
                <div className="flex items-center gap-4">
                    <h2 className="text-2xl font-bold bg-gradient-to-r from-primary-400 to-orange-400 bg-clip-text text-transparent">Kitchen Command Center</h2>
                    <div className="flex bg-dark-900 border border-white/10 rounded-xl p-1">
                        <button
                            onClick={() => setActiveView('KITCHEN')}
                            className={`px-4 py-2 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 ${activeView === 'KITCHEN' ? 'bg-primary-500 text-dark-950' : 'text-slate-400 hover:text-white'}`}
                        >
                            <Utensils size={16} /> Kitchen
                        </button>
                        <button
                            onClick={() => setActiveView('REVIEWS')}
                            className={`px-4 py-2 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 ${activeView === 'REVIEWS' ? 'bg-primary-500 text-dark-950' : 'text-slate-400 hover:text-white'}`}
                        >
                            <Star size={16} /> Feedback
                        </button>
                    </div>
                </div>
                {userRole !== 'CHEF' && (
                    <button
                        onClick={() => setShowPOSModal(true)}
                        className="bg-primary-500 hover:bg-primary-400 text-dark-950 font-bold px-4 py-2 rounded-xl flex items-center gap-2 shadow-lg shadow-primary-500/20 active:scale-95 transition-all"
                    >
                        <ListOrdered size={20} />
                        Walk-In POS Order
                    </button>
                )}
            </div>

            {activeView === 'KITCHEN' ? (
                <>
                    {/* Top Stat Bar */}
                    <div className="flex flex-col md:flex-row gap-4 mb-8">
                        <div className="glass-dark border border-white/10 rounded-2xl p-6 flex items-center justify-between flex-1">
                            <div>
                                <p className="text-slate-400 text-sm font-medium mb-1">Pending Verification</p>
                                <h3 className="text-3xl font-bold text-white">
                                    {awaitingPaymentOrders.length} Orders
                                </h3>
                            </div>
                            <div className="h-12 w-12 bg-indigo-400/10 rounded-full flex items-center justify-center border border-indigo-400/20">
                                <CreditCard className="text-indigo-400" size={24} />
                            </div>
                        </div>

                        <div className="glass-dark border border-white/10 rounded-2xl p-6 flex items-center justify-between flex-1">
                            <div>
                                <p className="text-slate-400 text-sm font-medium mb-1">Kitchen Backlog</p>
                                <h3 className="text-3xl font-bold bg-gradient-to-r from-red-400 to-orange-400 bg-clip-text text-transparent">
                                    {queueSize} Items
                                </h3>
                            </div>
                            <div className="h-12 w-12 bg-red-400/10 rounded-full flex items-center justify-center border border-red-400/20">
                                <ListOrdered className="text-red-400" size={24} />
                            </div>
                        </div>

                        <div className="glass-dark border border-white/10 rounded-2xl p-6 flex items-center justify-between flex-1">
                            <div>
                                <p className="text-slate-400 text-sm font-medium mb-1">Ready for Service</p>
                                <h3 className="text-3xl font-bold bg-gradient-to-r from-green-400 to-emerald-500 bg-clip-text text-transparent">
                                    {readyOrders.length} Orders
                                </h3>
                            </div>
                            <div className="h-12 w-12 bg-green-400/10 rounded-full flex items-center justify-center border border-green-400/20">
                                <CheckCircle2 className="text-green-400" size={24} />
                            </div>
                        </div>
                    </div>

                    {/* Kanban Columns */}
                    <div className="flex flex-col xl:flex-row gap-6 flex-grow overflow-x-auto pb-4 custom-scrollbar">

                        {/* Column 0: Awaiting Payment (Hidden for Chefs) */}
                        {userRole !== 'CHEF' && (
                            <div className="glass-dark rounded-3xl p-6 border border-indigo-500/20 flex flex-col min-w-[300px] xl:min-w-[320px] flex-1 min-h-[400px] xl:min-h-[500px]">
                                <div className="flex items-center gap-2 mb-6 pb-4 border-b border-indigo-500/10">
                                    <CreditCard className="text-indigo-400" />
                                    <h3 className="font-bold text-lg text-slate-200 tracking-wide">VERIFY PAYMENT</h3>
                                    <span className="ml-auto bg-indigo-500/20 text-indigo-400 px-3 py-1 rounded-full text-xs font-bold border border-indigo-500/30">
                                        {awaitingPaymentOrders.length}
                                    </span>
                                </div>

                                <div className="overflow-y-auto pr-2 space-y-4 flex-grow">
                                    {loading ? <LoadingSkeleton /> : <AnimatePresence>{awaitingPaymentOrders.map(order => OrderCard(order, null, advanceOrderState))}</AnimatePresence>}
                                    {!loading && awaitingPaymentOrders.length === 0 && <EmptyState icon={<CreditCard size={48} />} text="No pending payments" />}
                                </div>
                            </div>
                        )}

                        {/* Column 1: Queued */}
                        <div className="glass-dark rounded-3xl p-6 border border-white/5 flex flex-col min-w-[300px] xl:min-w-[320px] flex-1 min-h-[400px] xl:min-h-[500px]">
                            <div className="flex items-center gap-2 mb-6 pb-4 border-b border-white/5">
                                <ListOrdered className="text-slate-400" />
                                <h3 className="font-bold text-lg text-slate-200 tracking-wide">KITCHEN QUEUE</h3>
                                <span className="ml-auto bg-dark-800 text-slate-400 px-3 py-1 rounded-full text-xs font-bold border border-white/5">
                                    {queuedOrders.length}
                                </span>
                            </div>

                            <div className="overflow-y-auto pr-2 space-y-4 flex-grow">
                                {loading ? <LoadingSkeleton /> : <AnimatePresence>{queuedOrders.map(order => OrderCard(order, null, advanceOrderState))}</AnimatePresence>}
                                {!loading && queuedOrders.length === 0 && <EmptyState icon={<ListOrdered size={48} />} text="Queue is empty" />}
                            </div>
                        </div>

                        {/* Column 2: Preparing */}
                        <div className="bg-gradient-to-b from-dark-900/80 to-dark-800/40 backdrop-blur-xl rounded-3xl p-6 border border-primary-500/20 shadow-2xl flex flex-col min-w-[300px] xl:min-w-[350px] flex-1 min-h-[400px] xl:min-h-[500px] relative overflow-hidden">
                            <div className="absolute top-0 right-0 w-64 h-64 bg-primary-500/10 rounded-full -mr-32 -mt-32 blur-3xl pointer-events-none"></div>

                            <div className="flex items-center gap-2 mb-6 pb-4 border-b border-primary-500/10 z-10">
                                <ChefHat className="text-primary-500 animate-pulse" />
                                <h3 className="font-bold text-lg text-white tracking-wide">PREPARING</h3>
                                <span className="ml-auto bg-primary-500/20 text-primary-400 px-3 py-1 rounded-full text-xs font-bold border border-primary-500/30">
                                    {preparingOrders.length}
                                </span>
                            </div>

                            <div className="overflow-y-auto pr-2 space-y-4 flex-grow z-10">
                                {loading ? <LoadingSkeleton /> : (
                                    <AnimatePresence>
                                        {preparingOrders.map(order => OrderCard(order, markItemReady, advanceOrderState))}
                                    </AnimatePresence>
                                )}
                                {!loading && preparingOrders.length === 0 && <EmptyState active icon={<Utensils size={48} />} text="Kitchen is waiting" />}
                            </div>
                        </div>

                        {/* Column 3: Ready */}
                        <div className="glass-dark rounded-3xl p-6 border border-green-500/20 flex flex-col min-w-[300px] xl:min-w-[320px] flex-1 min-h-[400px] xl:min-h-[500px]">
                            <div className="flex items-center gap-2 mb-6 pb-4 border-b border-green-500/10">
                                <CheckCircle2 className="text-green-500" />
                                <h3 className="font-bold text-lg text-white tracking-wide">READY TO SERVE</h3>
                                <span className="ml-auto bg-green-500/20 text-green-400 px-3 py-1 rounded-full text-xs font-bold border border-green-500/30">
                                    {readyOrders.length}
                                </span>
                            </div>

                            <div className="overflow-y-auto pr-2 space-y-4 flex-grow">
                                {loading ? <LoadingSkeleton /> : <AnimatePresence>{readyOrders.map(order => OrderCard(order, null, advanceOrderState))}</AnimatePresence>}
                                {!loading && readyOrders.length === 0 && <EmptyState icon={<CheckCircle2 size={48} />} text="No orders awaiting service" />}
                            </div>
                        </div>
                    </div>
                </>
            ) : (
                <div className="glass-dark border border-white/5 rounded-3xl p-6">
                    <div className="flex items-center justify-between mb-8">
                        <div>
                            <h2 className="text-2xl font-bold text-white flex items-center gap-2"><MessageSquare className="text-primary-400" /> Customer Feedback</h2>
                            <p className="text-slate-400 mt-1">Review ratings and comments left by your completed orders.</p>
                        </div>
                        <div className="flex items-center gap-4 glass-dark p-4 rounded-2xl border border-white/5">
                            <div className="text-center">
                                <div className="text-3xl font-bold text-primary-400">
                                    {reviews.length > 0 ? (reviews.reduce((acc, r) => acc + r.rating, 0) / reviews.length).toFixed(1) : '0.0'}
                                </div>
                                <div className="text-xs text-slate-500 uppercase tracking-wider font-bold mt-1">Avg Rating</div>
                            </div>
                            <div className="w-px h-12 bg-white/10"></div>
                            <div className="text-center">
                                <div className="text-3xl font-bold text-white">{reviews.length}</div>
                                <div className="text-xs text-slate-500 uppercase tracking-wider font-bold mt-1">Total Reviews</div>
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                        {reviews.length === 0 ? (
                            <div className="col-span-full py-12">
                                <EmptyState icon={<Star size={48} />} text="No reviews yet" />
                            </div>
                        ) : (
                            reviews.map(r => (
                                <div key={r.id} className="bg-white/5 border border-white/10 rounded-2xl p-5 hover:border-primary-500/30 transition-colors flex flex-col">
                                    <div className="flex justify-between items-start mb-4">
                                        <div className="flex flex-col gap-1">
                                            <span className="font-bold text-white">Order #{r.order}</span>
                                            <div className="flex gap-1">
                                                {[...Array(5)].map((_, i) => (
                                                    <Star key={i} size={14} className={i < r.rating ? 'text-primary-500 fill-current' : 'text-slate-600'} />
                                                ))}
                                            </div>
                                        </div>
                                        <span className="text-xs font-bold text-slate-500 bg-white/5 px-2 py-1 rounded-md">
                                            {new Date(r.created_at).toLocaleDateString()}
                                        </span>
                                    </div>
                                    <p className="text-sm text-slate-300 italic flex-grow">"{r.comment || 'No comment provided.'}"</p>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            )}

            {/* Manual POS Modal Overlay */}
            {showPOSModal && (
                <div className="fixed inset-0 bg-dark-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <div className="bg-dark-900 border border-white/10 w-full max-w-4xl rounded-3xl shadow-2xl flex flex-col max-h-[90vh] overflow-hidden">

                        <div className="p-6 border-b border-white/10 flex justify-between items-center bg-dark-950/50">
                            <h2 className="text-2xl font-bold flex items-center gap-3">
                                <SquareTerminal className="text-primary-500" /> Walk-In POS Order
                            </h2>
                            <button onClick={() => setShowPOSModal(false)} className="text-slate-400 hover:text-white p-2">✕</button>
                        </div>

                        <div className="flex flex-col md:flex-row flex-1 overflow-hidden">
                            {/* Product List */}
                            <div className="flex-1 border-r border-white/10 flex flex-col bg-dark-950/30">
                                <div className="p-4 border-b border-white/5 font-semibold text-slate-300">Tap to Add Items</div>
                                <div className="p-4 overflow-y-auto grid grid-cols-2 lg:grid-cols-3 gap-3">
                                    {posProducts.map(p => (
                                        <button
                                            key={p.id}
                                            onClick={() => {
                                                const existing = posCart.find(item => item.product.id === p.id);
                                                if (existing) {
                                                    setPosCart(posCart.map(i => i.product.id === p.id ? { ...i, qty: i.qty + 1 } : i));
                                                } else {
                                                    setPosCart([...posCart, { product: p, qty: 1 }]);
                                                }
                                            }}
                                            className="bg-white/5 hover:bg-white/10 border border-white/5 rounded-xl p-3 text-left transition-colors flex flex-col gap-1 active:scale-95"
                                        >
                                            <span className="font-bold text-sm text-slate-200 line-clamp-1">{p.name}</span>
                                            <span className="text-xs text-primary-400 font-bold">${p.price}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Cart Sidebar */}
                            <div className="w-full md:w-80 flex flex-col bg-dark-900">
                                <div className="p-4 border-b border-white/10">
                                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Customer Name (Optional)</label>
                                    <input
                                        type="text"
                                        value={posCustomerName}
                                        onChange={e => setPosCustomerName(e.target.value)}
                                        placeholder="Walk-In Guest"
                                        className="w-full bg-dark-950 border border-white/10 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-primary-500"
                                    />
                                </div>

                                <div className="flex-1 overflow-y-auto p-4 space-y-3">
                                    {posCart.map(item => (
                                        <div key={item.product.id} className="flex justify-between items-center bg-white/5 p-2 rounded-lg border border-white/5">
                                            <div className="truncate pr-2">
                                                <div className="font-medium text-sm truncate w-32">{item.product.name}</div>
                                                <div className="text-xs text-slate-400">${item.product.price} x {item.qty}</div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <button
                                                    onClick={() => {
                                                        if (item.qty <= 1) setPosCart(posCart.filter(i => i.product.id !== item.product.id));
                                                        else setPosCart(posCart.map(i => i.product.id === item.product.id ? { ...i, qty: i.qty - 1 } : i));
                                                    }}
                                                    className="w-6 h-6 rounded bg-dark-800 text-white flex items-center justify-center hover:bg-red-500/20 hover:text-red-400"
                                                >-</button>
                                                <span className="text-sm font-bold w-4 text-center">{item.qty}</span>
                                                <button
                                                    onClick={() => setPosCart(posCart.map(i => i.product.id === item.product.id ? { ...i, qty: i.qty + 1 } : i))}
                                                    className="w-6 h-6 rounded bg-dark-800 text-white flex items-center justify-center hover:bg-green-500/20 hover:text-green-400"
                                                >+</button>
                                            </div>
                                        </div>
                                    ))}
                                    {posCart.length === 0 && <div className="text-center text-slate-500 text-sm mt-10">Cart is empty</div>}
                                </div>

                                <div className="p-4 border-t border-white/10 bg-dark-950/50">
                                    <div className="flex justify-between font-bold mb-4">
                                        <span>Total</span>
                                        <span className="text-primary-400">
                                            ${posCart.reduce((sum, item) => sum + (parseFloat(item.product.price) * item.qty), 0).toFixed(2)}
                                        </span>
                                    </div>
                                    <button
                                        disabled={posCart.length === 0}
                                        onClick={() => {
                                            const total = posCart.reduce((sum, item) => sum + (parseFloat(item.product.price) * item.qty), 0);
                                            const payload = {
                                                store_id: 1, // Assumption: Local POS attached to Store 1
                                                fulfillment_mode: 'TAKEAWAY',
                                                state: 'PAID', // Instantly paid at counter
                                                total_amount: total.toFixed(2),
                                                customer_name: posCustomerName || 'Walk-In Guest',
                                                items: posCart.map(i => ({ product_id: i.product.id, quantity: i.qty, price_at_time: i.product.price }))
                                            };

                                            const toastId = toast.loading('Dispatching ticket...');
                                            apiClient.post('/orders/', payload)
                                                .then(() => {
                                                    toast.success('Order fired to kitchen!', { id: toastId });
                                                    setPosCart([]);
                                                    setPosCustomerName('');
                                                    setShowPOSModal(false);
                                                    fetchDashboard();
                                                })
                                                .catch(err => toast.error('Failed to create order', { id: toastId }));
                                        }}
                                        className="w-full py-3 bg-primary-500 hover:bg-primary-400 text-dark-900 font-bold rounded-xl disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                    >
                                        Fire to Kitchen (Paid)
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

// Subcomponents

const OrderCard = (order, markItemReadyFn = null, advanceOrderStateFn = null) => {

    const isAwaitingPayment = order.state === 'AWAITING_PAYMENT';
    const isQueued = order.state === 'QUEUED' || order.state === 'PAID';
    const isPreparing = order.state === 'PREPARING';
    const isReadyColumn = order.state === 'READY';

    return (
        <motion.div
            layout
            initial={{ opacity: 0, scale: 0.95, y: 10 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: -10 }}
            key={order.id}
            className={`bg-dark-950/80 rounded-2xl p-5 border shadow-lg 
                ${isReadyColumn ? 'border-green-500/30 shadow-green-500/10' :
                    isPreparing ? 'border-primary-500/30 shadow-primary-500/10' :
                        isAwaitingPayment ? 'border-indigo-500/30 shadow-indigo-500/10' : 'border-white/5'
                }`}
        >
            <div className="flex justify-between items-start mb-4">
                <div>
                    <span className="text-xs font-bold text-slate-500 uppercase tracking-widest pl-1">Order</span>
                    <h4 className="text-2xl font-black text-white leading-none">#{order.id}</h4>
                    <span className="text-xs text-primary-400 font-bold block mt-1">${order.total_amount}</span>
                    <span className="text-xs text-slate-400 block mt-1">
                        {new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                    <span className="text-xs text-indigo-300 font-medium block mt-1">
                        {order.customer_name ? `By ${order.customer_name}` : 'Guest Order'}
                    </span>
                </div>

                <div className="flex flex-col items-end gap-2">
                    <span className={`px-3 py-1 rounded-lg text-xs font-bold ${order.fulfillment_mode === 'DINE_IN' ? 'bg-indigo-500/20 text-indigo-400 border border-indigo-500/30' :
                        'bg-orange-500/20 text-orange-400 border border-orange-500/30'
                        }`}>
                        {order.fulfillment_mode === 'DINE_IN' ? '🍽️ Dine In' : '🥡 Takeaway'}
                    </span>

                    {order.table_number && (
                        <span className="bg-slate-800 text-white px-3 py-1 rounded-lg text-xs font-bold border border-slate-700 flex items-center gap-1">
                            Table {order.table_number}
                        </span>
                    )}

                    {order.fulfillment_mode === 'DELIVERY' && (
                        <div className="mt-2 text-right bg-dark-900 border border-white/5 p-2 rounded-lg">
                            <span className="text-xs text-slate-400 block mb-1">📞 {order.customer_phone || 'No phone'}</span>
                            <span className="text-xs text-slate-300 block break-words max-w-[200px]">📍 {order.delivery_location || 'No location provided'}</span>
                        </div>
                    )}
                </div>
            </div>

            <div className="space-y-3 mt-4">
                {order.items?.map((item, idx) => (
                    <div key={item.id || idx} className="flex justify-between items-center bg-dark-800/50 rounded-xl p-3 border border-white/5">
                        <div className="flex items-center gap-3">
                            <span className="bg-dark-900 border border-white/10 text-white w-8 h-8 rounded-lg flex items-center justify-center font-bold text-sm">
                                {item.quantity}
                            </span>
                            <span className={`text-sm font-medium pr-2 ${item.is_ready ? 'text-slate-500 line-through' : 'text-slate-200'}`}>
                                {item.product.name ? item.product.name : 'Unknown Item'}
                            </span>
                        </div>

                        {item.is_ready ? (
                            <span className="flex items-center gap-1 text-green-500 text-xs font-bold bg-green-500/10 px-2 py-1 rounded shrink-0">
                                <CheckCircle2 size={14} /> Ready
                            </span>
                        ) : (
                            markItemReadyFn && isPreparing && (
                                <button
                                    onClick={() => markItemReadyFn(order.id, item.id)}
                                    className="bg-primary-500 hover:bg-primary-400 text-dark-900 text-xs font-bold px-3 py-2 rounded-lg transition-transform hover:scale-105 active:scale-95 shadow-lg shadow-primary-500/20 shrink-0"
                                >
                                    Finish
                                </button>
                            )
                        )}
                    </div>
                ))}
            </div>

            {isAwaitingPayment && (order.payment_message || order.payment_receipt) && (
                <div className="mt-4 bg-dark-900 border border-indigo-500/20 rounded-xl p-3 text-sm text-slate-300">
                    <p className="text-xs font-bold text-indigo-400 mb-1 uppercase tracking-wider">Proof of Payment</p>
                    {order.payment_message && <p className="mb-2 italic">"{order.payment_message}"</p>}
                    {order.payment_receipt && (
                        <a href={order.payment_receipt} target="_blank" rel="noreferrer" className="block mt-2 rounded-lg overflow-hidden border border-white/10 hover:border-indigo-500/50 transition-colors cursor-zoom-in">
                            <img src={order.payment_receipt} alt="Payment Receipt" className="w-full max-h-32 object-cover" />
                        </a>
                    )}
                </div>
            )}

            {isAwaitingPayment && (
                <button
                    onClick={() => advanceOrderStateFn(order.id, 'PAID')}
                    className="w-full mt-5 bg-indigo-500 hover:bg-indigo-400 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-indigo-500/20 flex items-center justify-center gap-2"
                >
                    <CheckCircle2 size={18} /> Verify Payment
                </button>
            )}

            {isQueued && advanceOrderStateFn && (
                <button
                    onClick={() => advanceOrderStateFn(order.id, 'PREPARING')}
                    className="w-full mt-5 bg-dark-800 hover:bg-dark-700 border border-white/10 text-white font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2"
                >
                    <Play size={18} className="text-primary-500" /> Start PREPARING
                </button>
            )}

            {isPreparing && advanceOrderStateFn && (
                <button
                    onClick={() => advanceOrderStateFn(order.id, 'READY')}
                    className="w-full mt-5 bg-primary-500 hover:bg-primary-400 text-dark-900 font-bold py-3 rounded-xl transition-all shadow-lg shadow-primary-500/20 flex items-center justify-center gap-2"
                >
                    <CheckCircle2 size={18} /> Mark All Ready
                </button>
            )}

            {isReadyColumn && (
                <button
                    onClick={() => advanceOrderStateFn(order.id, 'COMPLETED')}
                    className="w-full mt-5 bg-green-500 hover:bg-green-400 text-dark-900 font-bold py-3 rounded-xl transition-all shadow-lg shadow-green-500/20 flex items-center justify-center gap-2"
                >
                    <CheckCircle2 size={20} /> Complete Order
                </button>
            )}
        </motion.div>
    );
}

const LoadingSkeleton = () => (
    <>
        {[1, 2, 3].map(i => (
            <div key={i} className="bg-dark-950/50 rounded-2xl p-5 border border-white/5 animate-pulse h-40"></div>
        ))}
    </>
);

const EmptyState = ({ icon, text, active = false }) => (
    <div className={`flex flex-col items-center justify-center h-full text-center ${active ? 'text-primary-500/50' : 'text-slate-600'}`}>
        <div className="mb-4 opacity-50">{icon}</div>
        <p className="font-medium">{text}</p>
    </div>
);

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAppStore } from '../store/useStore';
import { Lock, User, Loader2, Utensils, Phone } from 'lucide-react';
import toast from 'react-hot-toast';
import { motion } from 'framer-motion';
import apiClient from '../api/client';

export default function Signup() {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [phone, setPhone] = useState('');
    const [loading, setLoading] = useState(false);

    const login = useAppStore(state => state.login);
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        const toastId = toast.loading('Creating your account...');

        try {
            // 1. Register the new customer account publicly
            await apiClient.post('/register/', {
                username: username,
                password: password,
                phone_number: phone
            });

            toast.success('Account created! Logging you in...', { id: toastId });

            // 2. Automatically log them in immediately afterwards
            await login(username, password);
            navigate('/menu');

        } catch (error) {
            toast.error(error.response?.data?.username?.[0] || 'Registration failed. Try a different username.', { id: toastId });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-[80vh] flex items-center justify-center p-4">
            {/* Background decorative elements */}
            <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-primary-500/20 rounded-full blur-[100px] pointer-events-none"></div>
            <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-orange-500/10 rounded-full blur-[100px] pointer-events-none"></div>

            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className="w-full max-w-md glass-dark rounded-3xl p-8 border border-white/10 shadow-2xl relative z-10"
            >
                <div className="flex flex-col items-center mb-8">
                    <div className="bg-primary-500/10 p-4 rounded-2xl mb-4 border border-primary-500/20">
                        <Utensils size={40} className="text-primary-500" />
                    </div>
                    <h2 className="text-3xl font-bold tracking-tight text-white mb-2">Join Chapuu</h2>
                    <p className="text-slate-400 text-center">Create a new customer account to order food instantly.</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-300 ml-1">Username <span className="text-red-400">*</span></label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                <User size={18} className="text-slate-500" />
                            </div>
                            <input
                                type="text"
                                required
                                value={username}
                                onChange={(e) => setUsername(e.target.value)}
                                className="w-full bg-dark-900 border border-white/10 focus:border-primary-500 focus:ring-1 focus:ring-primary-500 rounded-xl py-3 pl-11 pr-4 text-slate-100 placeholder-slate-600 transition-all outline-none"
                                placeholder="Choose a username..."
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-300 ml-1">Phone Number</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                <Phone size={18} className="text-slate-500" />
                            </div>
                            <input
                                type="tel"
                                value={phone}
                                onChange={(e) => setPhone(e.target.value)}
                                className="w-full bg-dark-900 border border-white/10 focus:border-primary-500 focus:ring-1 focus:ring-primary-500 rounded-xl py-3 pl-11 pr-4 text-slate-100 placeholder-slate-600 transition-all outline-none"
                                placeholder="(Optional)"
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-300 ml-1">Password <span className="text-red-400">*</span></label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                <Lock size={18} className="text-slate-500" />
                            </div>
                            <input
                                type="password"
                                required
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                minLength={4}
                                className="w-full bg-dark-900 border border-white/10 focus:border-primary-500 focus:ring-1 focus:ring-primary-500 rounded-xl py-3 pl-11 pr-4 text-slate-100 placeholder-slate-600 transition-all outline-none"
                                placeholder="••••••••"
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full mt-8 bg-gradient-to-r from-primary-500 to-primary-600 hover:from-primary-400 hover:to-primary-500 text-dark-950 font-bold py-3.5 rounded-xl transition-all shadow-lg shadow-primary-500/20 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 transform hover:-translate-y-0.5 active:translate-y-0"
                    >
                        {loading ? <Loader2 className="animate-spin" size={20} /> : "Create Account"}
                    </button>
                </form>

                <div className="mt-8 pt-6 border-t border-white/10 text-center">
                    <p className="text-slate-400">
                        Already have an account?{' '}
                        <Link to="/login" className="text-primary-400 hover:text-primary-300 font-semibold transition-colors">
                            Sign In
                        </Link>
                    </p>
                </div>
            </motion.div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Link, useNavigate } from 'react-router-dom';
import { Store, MapPin, ChefHat, ArrowRight } from 'lucide-react';
import { useAppStore } from '../store/useStore';
import apiClient from '../api/client';
import toast from 'react-hot-toast';

export default function StoreSelection() {
    const [stores, setStores] = useState([]);
    const [loading, setLoading] = useState(true);
    const { setSelectedStore } = useAppStore();
    const navigate = useNavigate();

    useEffect(() => {
        const fetchStores = async () => {
            try {
                const response = await apiClient.get('/stores/');
                setStores(response.data);
            } catch (error) {
                toast.error('Failed to load stores');
                console.error(error);
            } finally {
                setLoading(false);
            }
        };

        fetchStores();
    }, []);

    const handleSelectStore = (store) => {
        setSelectedStore(store);
        navigate('/menu');
    };

    return (
        <div className="w-full max-w-6xl mx-auto py-8">
            <div className="mb-10">
                <h1 className="text-3xl font-bold text-white mb-2">Choose a Restaurant</h1>
                <p className="text-slate-400">Select where you'd like to order from today.</p>
            </div>

            {loading ? (
                <div className="flex justify-center py-20">
                    <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary-500"></div>
                </div>
            ) : stores.length === 0 ? (
                <div className="text-center py-20 glass-dark rounded-3xl border border-white/5">
                    <ChefHat size={48} className="mx-auto text-slate-500 mb-4" />
                    <h3 className="text-xl font-medium text-white mb-2">No restaurants available</h3>
                    <p className="text-slate-400">Please check back later.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {stores.map((store, index) => (
                        <motion.div
                            key={store.id}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: index * 0.1 }}
                            onClick={() => handleSelectStore(store)}
                            className="glass-dark border border-white/5 rounded-3xl overflow-hidden cursor-pointer hover:border-primary-500/50 transition-all group"
                        >
                            <div className="h-40 bg-gradient-to-br from-slate-800 to-slate-900 border-b border-white/5 flex items-center justify-center relative overflow-hidden">
                                {store.image ? (
                                    <img src={store.image} alt={store.name} className="w-full h-full object-cover" />
                                ) : (
                                    <Store size={48} className="text-white/10" />
                                )}
                            </div>

                            <div className="p-6">
                                <h3 className="text-xl font-bold text-white mb-2 group-hover:text-primary-400 transition-colors">
                                    {store.name}
                                </h3>
                                <div className="flex flex-col gap-1 text-slate-400 text-sm mb-6">
                                    <div className="flex items-start gap-2">
                                        <MapPin size={16} className="shrink-0 mt-0.5" />
                                        <span>{store.location}</span>
                                    </div>
                                    {(store.contact_phone || store.contact_email) && (
                                        <div className="flex flex-wrap gap-x-4 gap-y-1 mt-2 text-xs">
                                            {store.contact_phone && <span>📞 {store.contact_phone}</span>}
                                            {store.contact_email && <span>✉️ {store.contact_email}</span>}
                                        </div>
                                    )}
                                </div>

                                <div className="flex items-center justify-between mt-auto pt-4 border-t border-white/5">
                                    <span className="text-sm font-medium text-slate-300">View Menu</span>
                                    <div className="w-8 h-8 rounded-full bg-primary-500/10 flex items-center justify-center text-primary-500 group-hover:bg-primary-500 group-hover:text-dark-950 transition-all">
                                        <ArrowRight size={16} />
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import apiClient from '../api/client';
import { QRCodeSVG } from 'qrcode.react';
import { QrCode, Printer } from 'lucide-react';
import { useAppStore } from '../store/useStore';

export default function TableQRCodes() {
    const [tables, setTables] = useState([]);
    const [loading, setLoading] = useState(true);
    const storeAppUrl = window.location.origin;

    const [storeId, setStoreId] = useState(null);

    const [newTableNum, setNewTableNum] = useState('');
    const [newTableCap, setNewTableCap] = useState(2);
    const [submitting, setSubmitting] = useState(false);

    useEffect(() => {
        // Fetch seller's store first
        apiClient.get('/stores/')
            .then(res => {
                const stores = res.data;
                if (stores.length > 0) {
                    const sid = stores[0].id;
                    setStoreId(sid);
                    return apiClient.get(`/stores/${sid}/tables/`);
                } else {
                    setLoading(false);
                    return Promise.reject("No stores found.");
                }
            })
            .then(res => {
                if (res) {
                    setTables(res.data);
                    setLoading(false);
                }
            })
            .catch(err => {
                console.error(err);
                setLoading(false);
            });
    }, []);

    const printQRs = () => {
        window.print();
    };

    const handleAddTable = (e) => {
        e.preventDefault();
        if (!storeId || !newTableNum) return;
        setSubmitting(true);
        apiClient.post(`/stores/${storeId}/tables/`, { number: newTableNum, capacity: newTableCap })
            .then(res => {
                toast.success(`Table ${newTableNum} added!`);
                setTables([...tables, res.data]);
                setNewTableNum('');
                setNewTableCap(2);
                setSubmitting(false);
            })
            .catch(err => {
                toast.error("Failed to add table");
                setSubmitting(false);
            });
    };

    if (loading) return <div className="p-8 text-slate-400 animate-pulse">Loading tables...</div>;

    return (
        <div className="w-full max-w-6xl mx-auto py-8">
            <div className="flex justify-between items-end mb-8 print:hidden">
                <div className="flex items-center gap-4">
                    <div className="bg-primary-500/10 p-3 rounded-xl border border-primary-500/20">
                        <QrCode className="text-primary-500" size={32} />
                    </div>
                    <div>
                        <h2 className="text-3xl font-bold text-white">Table QR Generator</h2>
                        <p className="text-slate-400">Print these to stick on restaurant tables. Customers scan them to auto-order to their table.</p>
                    </div>
                </div>
                <div className="flex gap-4 items-center">
                    <form onSubmit={handleAddTable} className="flex gap-2 items-center bg-dark-900 border border-white/10 p-2 rounded-xl">
                        <input
                            type="text"
                            placeholder="Tbl Num"
                            value={newTableNum}
                            onChange={e => setNewTableNum(e.target.value)}
                            required
                            className="w-20 bg-dark-950 border border-white/10 rounded-lg px-2 py-2 text-sm text-slate-200 focus:border-primary-500 outline-none"
                        />
                        <input
                            type="number"
                            placeholder="Seats"
                            min="1"
                            value={newTableCap}
                            onChange={e => setNewTableCap(e.target.value)}
                            className="w-16 bg-dark-950 border border-white/10 rounded-lg px-2 py-2 text-sm text-slate-200 focus:border-primary-500 outline-none"
                        />
                        <button
                            type="submit"
                            disabled={submitting}
                            className="bg-primary-500/10 hover:bg-primary-500/20 text-primary-400 px-3 py-2 rounded-lg font-bold text-sm transition-colors"
                        >
                            {submitting ? '...' : '+ Add'}
                        </button>
                    </form>
                    <button
                        onClick={printQRs}
                        className="flex items-center gap-2 bg-primary-600 hover:bg-primary-500 text-dark-900 font-bold px-6 py-3 rounded-xl transition-all shadow-lg"
                    >
                        <Printer size={20} /> Print
                    </button>
                </div>
            </div>

            <style>
                {`
                    @media print {
                        body { background: white; color: black; }
                        .glass-dark, .bg-dark-950, .text-slate-400 { background: white !important; border: 1px solid #ccc !important; color: black !important; }
                        * { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                        nav { display: none !important; }
                    }
                `}
            </style>

            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-8 print:gap-12 print:grid-cols-3">
                {tables.map(t => {
                    // Deep Link URL for auto-assigning Store, Table, and Fulfillment Mode
                    const scanUrl = `${storeAppUrl}/menu?store=${storeId}&table=${t.id}&mode=DINE_IN`;
                    return (
                        <div key={t.id} className="glass-dark rounded-3xl p-6 border border-white/10 flex flex-col items-center text-center print:border-slate-300 print:shadow-none break-inside-avoid">
                            <h3 className="text-2xl font-black text-white print:text-black mb-1">TABLE {t.number}</h3>
                            <p className="text-sm text-slate-400 print:text-slate-600 mb-6">{t.capacity} Seats</p>

                            <div className="bg-white p-4 rounded-2xl border-2 border-white/20 print:border-slate-200 mb-6 shadow-xl">
                                <QRCodeSVG
                                    value={scanUrl}
                                    size={160}
                                    bgColor={"#ffffff"}
                                    fgColor={"#0f172a"}
                                    level={"M"}
                                />
                            </div>

                            <p className="text-sm font-medium text-primary-400 print:text-slate-800">Scan to Order</p>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import apiClient from '../../api/client';
import { Plus, Edit2, Trash2, Save, X, Tag, Package, Image as ImageIcon } from 'lucide-react';
import toast from 'react-hot-toast';

export default function MenuBuilder() {
    const [categories, setCategories] = useState([]);
    const [products, setProducts] = useState([]);
    const [loading, setLoading] = useState(true);

    // Form logic
    const [editingCategory, setEditingCategory] = useState(null);
    const [editingProduct, setEditingProduct] = useState(null);
    const [productImageFile, setProductImageFile] = useState(null);

    const [storeId, setStoreId] = useState(null);

    const fetchData = (sid) => {
        setLoading(true);
        Promise.all([
            apiClient.get(`/categories/?store=${sid}`),
            apiClient.get(`/products/?store=${sid}`)
        ]).then(([catRes, prodRes]) => {
            setCategories(catRes.data);
            setProducts(prodRes.data);
            setLoading(false);
        }).catch(err => {
            toast.error("Failed to load catalog data");
            setLoading(false);
        });
    };

    useEffect(() => {
        apiClient.get('/stores/')
            .then(res => {
                if (res.data.length > 0) {
                    const sid = res.data[0].id;
                    setStoreId(sid);
                    fetchData(sid);
                } else {
                    setLoading(false);
                    toast.error("You don't have an active store to manage.");
                }
            })
            .catch(err => {
                console.error(err);
                setLoading(false);
            });
    }, []);

    // --- Category Logic ---
    const handleSaveCategory = (e) => {
        e.preventDefault();
        const toastId = toast.loading("Saving category...");
        const payload = {
            store: storeId,
            name: editingCategory.name
        };

        const req = editingCategory.id
            ? apiClient.put(`/categories/${editingCategory.id}/`, payload)
            : apiClient.post(`/categories/`, payload);

        req.then(() => {
            toast.success("Category saved!", { id: toastId });
            setEditingCategory(null);
            if (storeId) fetchData(storeId);
        }).catch(err => toast.error("Error saving category.", { id: toastId }));
    };

    const handleDeleteCategory = (id) => {
        if (!window.confirm("Delete this category? Products in it will be uncategorized.")) return;
        apiClient.delete(`/categories/${id}/`).then(() => { if (storeId) fetchData(storeId); }).catch(() => toast.error("Failed to delete"));
    };

    // --- Product Logic ---
    const handleSaveProduct = (e) => {
        e.preventDefault();
        const toastId = toast.loading("Saving product...");

        const formData = new FormData();
        formData.append('store', storeId);
        formData.append('name', editingProduct.name);
        formData.append('description', editingProduct.description);
        formData.append('price', editingProduct.price);
        if (editingProduct.category) {
            formData.append('category', editingProduct.category);
        }
        formData.append('requires_kitchen', editingProduct.requires_kitchen);
        formData.append('is_active', editingProduct.is_active);

        if (productImageFile) {
            formData.append('image', productImageFile);
        }

        const req = editingProduct.id
            ? apiClient.put(`/products/${editingProduct.id}/`, formData, { headers: { 'Content-Type': 'multipart/form-data' } })
            : apiClient.post(`/products/`, formData, { headers: { 'Content-Type': 'multipart/form-data' } });

        req.then(() => {
            toast.success("Product saved!", { id: toastId });
            setEditingProduct(null);
            setProductImageFile(null);
            if (storeId) fetchData(storeId);
        }).catch(err => toast.error("Error saving product.", { id: toastId }));
    };

    const handleDeleteProduct = (id) => {
        if (!window.confirm("Delete this product permanently?")) return;
        apiClient.delete(`/products/${id}/`).then(() => { if (storeId) fetchData(storeId); }).catch(() => toast.error("Failed to delete"));
    };

    if (loading) return <div className="p-8 text-white flex justify-center"><div className="animate-spin rounded-full h-12 w-12 border-t-2 border-primary-500"></div></div>;

    return (
        <div className="w-full max-w-7xl mx-auto py-8 text-white">
            <div className="mb-8 flex justify-between items-end">
                <div>
                    <h1 className="text-3xl font-bold mb-2">Menu Builder</h1>
                    <p className="text-slate-400">Create categories and products for your restaurant.</p>
                </div>
            </div>

            <div className="flex flex-col lg:flex-row gap-8">

                {/* Categories Column */}
                <div className="w-full lg:w-1/3 space-y-6">
                    <div className="glass-dark border border-white/10 rounded-3xl p-6">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-xl font-bold flex items-center gap-2"><Tag className="text-primary-500" size={20} /> Categories</h2>
                            <button
                                onClick={() => setEditingCategory({ name: '' })}
                                className="bg-primary-500/10 hover:bg-primary-500/20 text-primary-400 p-2 rounded-lg transition-colors"
                            >
                                <Plus size={18} />
                            </button>
                        </div>

                        {editingCategory && (
                            <form onSubmit={handleSaveCategory} className="mb-6 bg-dark-900 border border-primary-500/30 p-4 rounded-xl">
                                <input
                                    type="text"
                                    placeholder="Category Name"
                                    required
                                    value={editingCategory.name}
                                    onChange={e => setEditingCategory({ ...editingCategory, name: e.target.value })}
                                    className="w-full bg-dark-950 border border-white/10 rounded-lg px-3 py-2 mb-3 text-sm focus:border-primary-500 outline-none"
                                />
                                <div className="flex gap-2">
                                    <button type="submit" className="flex-1 bg-primary-500 text-dark-900 font-bold py-2 rounded-lg text-sm">Save</button>
                                    <button type="button" onClick={() => setEditingCategory(null)} className="flex-1 bg-white/5 hover:bg-white/10 text-white font-medium py-2 rounded-lg text-sm">Cancel</button>
                                </div>
                            </form>
                        )}

                        <div className="space-y-3">
                            {categories.map(c => (
                                <div key={c.id} className="flex justify-between items-center bg-dark-900/50 p-3 rounded-xl border border-white/5 hover:border-white/10 transition-colors">
                                    <span className="font-medium">{c.name}</span>
                                    <div className="flex gap-2">
                                        <button onClick={() => setEditingCategory(c)} className="text-slate-400 hover:text-white p-1"><Edit2 size={16} /></button>
                                        <button onClick={() => handleDeleteCategory(c.id)} className="text-slate-400 hover:text-red-400 p-1"><Trash2 size={16} /></button>
                                    </div>
                                </div>
                            ))}
                            {categories.length === 0 && <p className="text-sm text-slate-500 text-center py-4">No categories yet.</p>}
                        </div>
                    </div>
                </div>

                {/* Products Column */}
                <div className="w-full lg:w-2/3 space-y-6">
                    <div className="glass-dark border border-white/10 rounded-3xl p-6">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-xl font-bold flex items-center gap-2"><Package className="text-primary-500" size={20} /> Products</h2>
                            <button
                                onClick={() => {
                                    setEditingProduct({ name: '', description: '', price: '', category: '', requires_kitchen: true, is_active: true });
                                    setProductImageFile(null);
                                }}
                                className="bg-primary-500 hover:bg-primary-400 text-dark-900 font-bold px-4 py-2 rounded-xl transition-all flex items-center gap-2 shadow-lg shadow-primary-500/20"
                            >
                                <Plus size={18} /> Add Product
                            </button>
                        </div>

                        {editingProduct && (
                            <form onSubmit={handleSaveProduct} className="mb-8 bg-dark-900 border border-primary-500/30 p-6 rounded-2xl shadow-xl">
                                <h3 className="text-lg font-bold mb-4">{editingProduct.id ? 'Edit Product' : 'New Product'}</h3>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                                    <div>
                                        <label className="text-xs text-slate-400 mb-1 block">Name</label>
                                        <input type="text" required value={editingProduct.name} onChange={e => setEditingProduct({ ...editingProduct, name: e.target.value })} className="w-full bg-dark-950 border border-white/10 rounded-lg px-3 py-2 text-sm focus:border-primary-500 outline-none" />
                                    </div>
                                    <div>
                                        <label className="text-xs text-slate-400 mb-1 block">Price</label>
                                        <input type="number" step="0.01" required value={editingProduct.price} onChange={e => setEditingProduct({ ...editingProduct, price: e.target.value })} className="w-full bg-dark-950 border border-white/10 rounded-lg px-3 py-2 text-sm focus:border-primary-500 outline-none" />
                                    </div>
                                    <div className="md:col-span-2">
                                        <label className="text-xs text-slate-400 mb-1 block">Description</label>
                                        <textarea value={editingProduct.description} onChange={e => setEditingProduct({ ...editingProduct, description: e.target.value })} className="w-full bg-dark-950 border border-white/10 rounded-lg px-3 py-2 text-sm focus:border-primary-500 outline-none h-20" />
                                    </div>
                                    <div>
                                        <label className="text-xs text-slate-400 mb-1 block">Category</label>
                                        <select value={editingProduct.category || ''} onChange={e => setEditingProduct({ ...editingProduct, category: e.target.value })} className="w-full bg-dark-950 border border-white/10 rounded-lg px-3 py-2 text-sm focus:border-primary-500 outline-none">
                                            <option value="">No Category</option>
                                            {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                        </select>
                                    </div>
                                    <div className="md:col-span-2">
                                        <label className="text-xs text-slate-400 mb-1 block">Product Image</label>
                                        <input
                                            type="file"
                                            accept="image/*"
                                            onChange={e => setProductImageFile(e.target.files[0])}
                                            className="w-full bg-dark-950 border border-white/10 rounded-lg px-3 py-2 text-sm focus:border-primary-500 outline-none file:mr-4 file:py-1 file:px-3 file:rounded-md file:border-0 file:text-xs file:font-semibold file:bg-primary-500/10 file:text-primary-500 hover:file:bg-primary-500/20"
                                        />
                                    </div>
                                    <div className="flex items-center gap-6 pt-6 pb-2">
                                        <label className="flex items-center gap-2 cursor-pointer text-sm font-medium">
                                            <input type="checkbox" checked={editingProduct.requires_kitchen} onChange={e => setEditingProduct({ ...editingProduct, requires_kitchen: e.target.checked })} className="accent-primary-500 w-4 h-4 rounded" />
                                            Send to Kitchen
                                        </label>
                                        <label className="flex items-center gap-2 cursor-pointer text-sm font-medium">
                                            <input type="checkbox" checked={editingProduct.is_active} onChange={e => setEditingProduct({ ...editingProduct, is_active: e.target.checked })} className="accent-primary-500 w-4 h-4 rounded" />
                                            Actively Available
                                        </label>
                                    </div>
                                </div>
                                <div className="flex justify-end gap-3 pt-4 border-t border-white/10 mt-2">
                                    <button type="button" onClick={() => setEditingProduct(null)} className="px-5 py-2 hover:bg-white/5 rounded-lg text-sm font-medium transition-colors">Cancel</button>
                                    <button type="submit" className="bg-primary-500 hover:bg-primary-400 text-dark-900 px-6 py-2 rounded-lg text-sm font-bold shadow-lg shadow-primary-500/20">Save Product</button>
                                </div>
                            </form>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            {products.map(p => (
                                <div key={p.id} className="bg-dark-900/50 border border-white/5 rounded-2xl p-4 hover:border-white/10 transition-colors flex flex-col">
                                    {p.image && (
                                        <div className="w-full h-32 mb-3 rounded-xl overflow-hidden border border-white/5">
                                            <img src={p.image} alt={p.name} className="w-full h-full object-cover" />
                                        </div>
                                    )}
                                    <div className="flex justify-between items-start mb-2">
                                        <h3 className="font-bold text-lg">{p.name}</h3>
                                        <span className="font-bold text-primary-400">${p.price}</span>
                                    </div>
                                    <p className="text-sm text-slate-400 line-clamp-2 mb-4 flex-grow">{p.description}</p>

                                    <div className="flex items-center justify-between pt-3 border-t border-white/5 mt-auto">
                                        <div className="flex gap-2">
                                            {p.is_active ? <span className="bg-green-500/20 text-green-400 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider">Active</span> : <span className="bg-red-500/20 text-red-400 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider">Hidden</span>}
                                            {p.requires_kitchen && <span className="bg-orange-500/20 text-orange-400 text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider">Kitchen</span>}
                                        </div>
                                        <div className="flex gap-2">
                                            <button onClick={() => setEditingProduct({
                                                id: p.id,
                                                name: p.name,
                                                description: p.description,
                                                price: p.price,
                                                category: p.category,
                                                requires_kitchen: p.requires_kitchen,
                                                is_active: p.is_active
                                            })} className="p-2 text-slate-400 hover:text-white bg-white/5 rounded-lg"><Edit2 size={14} /></button>
                                            <button onClick={() => handleDeleteProduct(p.id)} className="p-2 text-slate-400 hover:text-red-400 bg-white/5 rounded-lg"><Trash2 size={14} /></button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                        {products.length === 0 && <p className="text-slate-500 text-center py-8">No products yet. Click "Add Product" to start building your menu!</p>}
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import apiClient from '../../api/client';
import { useAppStore } from '../../store/useStore';
import { MapPin, Phone, CheckCircle, Clock, Package, Navigation, LogOut } from 'lucide-react';
import toast from 'react-hot-toast';
import { motion } from 'framer-motion';

export default function DeliveryDashboard() {
    const { userRole, clearAuth } = useAppStore();
    const navigate = useNavigate();
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (userRole !== 'DELIVERY' && userRole !== 'ADMIN') {
            navigate('/');
            return;
        }

        const fetchOrders = () => {
            apiClient.get('/orders/')
                .then(res => {
                    // Filter for active delivery orders (READY or strictly PREPARING if they want to wait)
                    // Usually delivery picks up when READY. We'll show READY and PREPARING for awareness.
                    const deliveryOrders = res.data.filter(o =>
                        o.fulfillment_mode === 'DELIVERY' &&
                        ['PREPARING', 'READY'].includes(o.state)
                    );
                    setOrders(deliveryOrders);
                    setLoading(false);
                })
                .catch(err => {
                    console.error("Failed to load delivery orders", err);
                    setLoading(false);
                });
        };

        fetchOrders();
        const interval = setInterval(fetchOrders, 10000);
        return () => clearInterval(interval);
    }, [userRole, navigate]);

    const handleMarkDelivered = (orderId) => {
        if (!window.confirm("Confirm order has been delivered to customer?")) return;

        apiClient.patch(`/orders/${orderId}/`, { state: 'COMPLETED' })
            .then(() => {
                toast.success("Order marked as Delivered!");
                setOrders(orders.filter(o => o.id !== orderId));
            })
            .catch(err => {
                console.error("Failed to update order", err);
                toast.error("Failed to mark delivered.");
            });
    };

    if (loading) {
        return <div className="flex justify-center items-center h-screen"><div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary-500"></div></div>;
    }

    return (
        <div className="w-full max-w-6xl mx-auto py-8 text-white px-4">
            <div className="flex items-center justify-between mb-8">
                <div>
                    <h1 className="text-3xl font-bold flex items-center gap-3">
                        <Navigation size={32} className="text-primary-500" />
                        Delivery Dispatch
                    </h1>
                    <p className="text-slate-400 mt-1">Manage active delivery orders</p>
                </div>
                {userRole === 'DELIVERY' && (
                    <button
                        onClick={() => { clearAuth(); navigate('/login'); }}
                        className="flex items-center gap-2 p-2 bg-red-500/10 text-red-500 hover:bg-red-500/20 rounded-xl transition-colors font-medium"
                    >
                        <LogOut size={20} /> <span className="hidden sm:inline">Sign Out</span>
                    </button>
                )}
            </div>

            {orders.length === 0 ? (
                <div className="glass-dark border border-white/10 rounded-3xl p-16 text-center">
                    <Package size={48} className="mx-auto text-slate-600 mb-4" />
                    <h2 className="text-2xl font-bold mb-2">No Active Deliveries</h2>
                    <p className="text-slate-400">Waiting for new delivery orders to be ready...</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {orders.map(order => (
                        <motion.div
                            key={order.id}
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            className={`glass-dark border rounded-3xl p-6 shadow-xl relative overflow-hidden flex flex-col ${order.state === 'READY' ? 'border-primary-500/50' : 'border-white/10'}`}
                        >
                            {order.state === 'READY' && (
                                <div className="absolute top-0 left-0 w-full h-1 bg-primary-500 shadow-[0_0_10px_rgba(249,115,22,0.8)]"></div>
                            )}

                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <span className="text-xs font-bold tracking-wider text-slate-500 uppercase">Order #{order.id}</span>
                                    <h3 className="text-xl font-bold">{order.store_name || `Store #${order.store}`}</h3>
                                </div>
                                <span className={`px-3 py-1 rounded-lg text-xs font-bold ${order.state === 'READY' ? 'bg-primary-500/20 text-primary-400' : 'bg-white/10 text-slate-300'}`}>
                                    {order.state === 'READY' ? 'Ready for Pickup' : 'Cooking...'}
                                </span>
                            </div>

                            <div className="space-y-4 flex-grow mb-6">
                                <div className="bg-dark-900/50 p-4 rounded-xl border border-white/5">
                                    <div className="flex items-start gap-3 mb-3">
                                        <MapPin size={18} className="text-slate-400 mt-0.5 shrink-0" />
                                        <div>
                                            <p className="text-xs text-slate-500 uppercase font-semibold mb-1">Deliver To</p>
                                            <p className="text-sm font-medium">{order.delivery_location || 'No location provided'}</p>
                                        </div>
                                    </div>
                                    <div className="flex items-start gap-3">
                                        <Phone size={18} className="text-slate-400 mt-0.5 shrink-0" />
                                        <div>
                                            <p className="text-xs text-slate-500 uppercase font-semibold mb-1">Customer Phone</p>
                                            <p className="text-sm font-medium">{order.customer_phone || 'No phone provided'}</p>
                                        </div>
                                    </div>
                                </div>

                                <div>
                                    <p className="text-xs text-slate-500 uppercase font-semibold mb-2">Order Items</p>
                                    <div className="text-sm text-slate-300 space-y-1">
                                        {order.items.map(item => (
                                            <div key={item.id} className="flex justify-between border-b border-white/5 pb-1">
                                                <span>{item.quantity}x {item.product.name}</span>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="flex justify-between mt-2 font-bold text-primary-400">
                                        <span>Total to Collect (if unpaid):</span>
                                        <span>${order.total_amount}</span>
                                    </div>
                                </div>
                            </div>

                            <button
                                onClick={() => handleMarkDelivered(order.id)}
                                disabled={order.state !== 'READY'}
                                className={`w-full py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${order.state === 'READY'
                                    ? 'bg-green-500 hover:bg-green-400 text-dark-900 shadow-[0_0_15px_rgba(34,197,94,0.3)] hover:-translate-y-1'
                                    : 'bg-white/5 text-slate-500 cursor-not-allowed'
                                    }`}
                            >
                                {order.state === 'READY' ? (
                                    <><CheckCircle size={20} /> Mark Delivered</>
                                ) : (
                                    <><Clock size={20} /> Waiting on Kitchen</>
                                )}
                            </button>
                        </motion.div>
                    ))}
                </div>
            )}
        </div>
    );
}
